output.rtl/priority_encoder.v:
module priority_encoder_8x3 (
    input [7:0] in,
    output reg [2:0] out
);

    always @ (in) begin
        if (in[7]) begin
            out = 3'b111;
        end else if (in[6]) begin
            out = 3'b110;
        end else if (in[5]) begin
            out = 3'b101;
        end else if (in[4]) begin
            out = 3'b011;
        end else if (in[3]) begin
            out = 3'b010;
        end else if (in[2]) begin
            out = 3'b001;
        end else if (in[1]) begin
            out = 3'b000;
        end
    end

endmodule

input.rtl/priority_encoder.v:
module priority_encoder_8x3 (
    input       [7:0] in      ,   // 8 input lines
    output reg  [2:0] out         // 3 output lines
);

always @(*) begin
    if (in[7])
        out = 3'b111;
    else if (in[6])
        out = 3'b110;
    else if (in[5])
        out = 3'b101;
    else if (in[4])
        out = 3'b100;
    else if (in[3])
        out = 3'b011;
    else if (in[2])
        out = 3'b010;
    else if (in[1])
        out = 3'b001;
    else if (in[0])
        out = 3'b000;
    else
        out = 3'b000; // Default case when no inputs are active
end

