output.rtl/cascaded_encoder.v:
module cascaded_encoder #(parameter N = 8) (
    input [N-1:0] input_signal,
    output reg [N-1:0] out,
    output reg [N-2:0] out_upper_half,
    output reg [N-2:0] out_lower_half
);

    // Calculate the width of the output vector
    localparam M = N - 1; // Since N is the bit width of the input, M is the output bit width

    // Instantiate two parameterized priority encoders for upper and lower halves
    priority_encoder #(N, M) encoder_upper (
        .input_signal(input_signal[N-1:N]),
        .out(out_upper_half)
    );

    priority_encoder #(N, M) encoder_lower (
        .input_signal(input_signal[0:N-1]),
        .out(out_lower_half)
    );

    // Determine which half has the highest priority input
    always @(input_signal) begin
        if (out_upper_half[M-1] == 1'b1) begin
            out = out_upper_half;
            out_lower_half = 32'h0; // Default LSB half to zero if MSB half is active
        end else if (out_lower_half[M-1] == 1'b1) begin
            out = out_lower_half;
            out_upper_half = 32'h0; // Default MSB half to zero if LSB half is active
        end else begin
            out = 32'h0; // No inputs are active
        end
    end

endmodule

output.rtl/Attenuator.sv:
module Attenuator (
    input        clk,
    input        reset,
    input  [4:0] data,
    output reg   ATTN_CLK,
    output reg   ATTN_DATA,
    output reg   ATTN_LE
);

// Internal Signals
reg        clk_div2;
reg  [1:0] current_state, next_state;
reg  [4:0] shift_reg;
reg  [2:0] bit_count;
reg  [4:0] old_data;

// Parameters for FSM States
localparam IDLE  = 2'b00,
           LOAD  = 2'b01,
           SHIFT = 2'b10,
           LATCH = 2'b11;

// Reset Condition
always @(posedge clk or posedge reset) begin
    if (reset) begin
        clk_div2 <= 1'b0;
        current_state <= IDLE;
        ATTN_CLK      <= 1'b0;
        ATTN_DATA     <= 1'b0;
        ATTN_LE       <= 1'b0;
        shift_reg     <= 5'b00000;
        bit_count     <= 3'd0;
        old_data      <= 5'b00000;
    end else begin
        case (current_state)
            IDLE: begin
                if (data != old_data) begin
                    current_state <= LOAD;
                end else begin
                    current_state <= IDLE;
                end
            end
            LOAD: begin
                shift_reg <= data;
                bit_count <= 5;
                current_state <= SHIFT;
            end
            SHIFT: begin
                ATTN_DATA <= shift_reg[bit_count];
                bit_count <= bit_count - 1;
                if (bit_count == 0) begin
                    current_state <= LATCH;
                end else begin
                    current_state <= SHIFT;
                end
            end
            LATCH: begin
                ATTN_LE <= 1'b1;
                @(posedge clk_div2); // Wait for the slower clock
                ATTN_LE <= 1'b0;
                current_state <= IDLE;
            end
        endcase
    end
end

endmodule

output.rtl/GP.v:
module Generate_Propagate (
    input i_A,
    input i_B,
    input i_Cin,
    output reg o_generate,
    output reg o_propagate,
    output o_Cout
);

    // Define the outputs based on the truth table
    always @(i_A, i_B, i_Cin) begin
        case ({i_A, i_B, i_Cin})
            000: o_generate = 0; o_propagate = 0; o_Cout = 0;
            001: o_generate = 0; o_propagate = 0; o_Cout = 0;
            010: o_generate = 0; o_propagate = 1; o_Cout = 0;
            011: o_generate = 0; o_propagate = 1; o_Cout = 1;
            100: o_generate = 0; o_propagate = 1; o_Cout = 0;
            101: o_generate = 0; o_propagate = 1; o_Cout = 1;
            110: o_generate = 1; o_propagate = 1; o_Cout = 1;
            111: o_generate = 1; o_propagate = 1; o_Cout = 1;
        endcase
    end

    // Calculate the carry-out based on generate, propagate, and carry-in
    always @(posedge i_A, posedge i_B, posedge i_Cin) begin
        if (i_Cin) begin
            o_Cout = o_generate | (o_propagate & i_Cin);
        end else begin
            o_Cout = o_generate | o_propagate;
        end
    end

endmodule

input.rtl/pipelined_adder_32bit.sv:
module pipelined_adder_32bit (
    input clk,       // Synchronous to posedge of clk 
    input reset,     // Synchronous active high reset
    input [31:0] A,  // 32 bit operand for addition  
    input [31:0] B,  // 32 bit operand for addition  
    input start,     // Active high signal to indicate when valid input data is provided
    output [31:0] S, // Final sum or result 
    output Co,       // Final carry out 
    output done      // Completion signal, active high when computation is complete    
);

    wire [7:0] A1, B1, A2, B2, A3, B3;
    wire carry1, carry2, carry3;
    wire [7:0] s13, s23, s12, A21, B21, A31, B31, A32, B32;
    wire [7:0] s1, s2, s3;
    wire control2, control1, control3, control4;

    dff #(1) FF00 (.clk(clk), .reset(reset), .D(1'b1), .Q(control1));

    dff #(8) FF11 (.clk(clk), .reset(reset), .D(A[15:8]), .Q(A1));
    dff #(8) FF12 (.clk(clk), .reset(reset), .D(B[15:8]), .Q(B1));
    dff #(8) FF13 (.clk(clk), .reset(reset), .D(A[23:16]), .Q(A2));
    dff #(8) FF14 (.clk(clk), .reset(reset), .D(B[23:16]), .Q(B2));
    dff #(8) FF15 (.clk(clk), .reset(reset), .D(A[31:24]), .Q(A3));
    dff #(8) FF16 (.clk(clk), .reset(reset), .D(B[31:24]), .Q(B3));

    carry_lookahead_adder #(8) ADD1 (.clk(clk), .reset(reset), .A(A[7:0]), .B(B[7:0]), .Cin(1'b0), .S(s1), .carry(carry1));

    dff #(1) FF01 (.clk(clk), .reset(reset), .D(control1), .Q(control2));

    dff #(8) FF21 (.clk(clk), .reset(reset), .D(s1), .Q(s12));
    dff #(8) FF23 (.clk(clk), .reset(reset), .D(A3), .Q(A21));
    dff #(8) FF24 (.clk(clk), .reset(reset), .D(B3), .Q(B21));
    dff #(8) FF25 (.clk(clk), .reset(reset), .D(A2), .Q(A31));
    dff #(8) FF26 (.clk(clk), .reset(reset), .D(B2), .Q(B31));

    carry_lookahead_adder #(8) ADD2 (.clk(clk), .reset(reset), .A(A1), .B(B1), .Cin(carry1), .S(s2), .carry(carry2));

    dff #(1) FF10 (.clk(clk), .reset(reset), .D(control2), .Q(control3));

    dff #(8) FF31 (.clk(clk), .reset(reset), .D(s2), .Q(s13));
    dff #(8) FF32 (.clk(clk), .reset(reset), .D(s12), .Q(s23));
    dff #(8) FF35 (.clk(clk), .reset(reset), .D(A31), .Q(A32));
    dff #(8) FF36 (.clk(clk), .reset(reset), .D(B31), .Q(B32));

    carry_lookahead_adder #(8) ADD3 (.clk(clk), .reset(reset), .A(A21), .B(B21), .Cin(carry2), .S(s3), .carry(carry3));

    dff #(1) FF111 (.clk(clk), .reset(reset), .D(control3), .Q(done));

    dff #(8) FF41 (.clk(clk), .reset(reset), .D(s13), .Q(S[7:0]));
    dff #(8) FF42 (.clk(clk), .reset(reset), .D(s23), .Q(S[15:8]));
    dff #(8) FF43 (.clk(clk), .reset(reset), .D(s3), .Q(S[23:16]));

    carry_lookahead_adder #(8) ADD4 (.clk(clk), .reset(reset), .A(A32), .B(B32), .Cin(carry3), .S(S[31:24]), .carry(Co));

endmodule

module carry_lookahead_adder #(parameter WIDTH = 32) (
    input [WIDTH-1:0] A,    // WIDTH bit operand for addition
    input [WIDTH-1:0] B,    // WIDTH bit operand for addition
    input Cin, clk, reset,  // Cin -> carry in, clk -> Synchronous to posedge of clk , reset -> Synchronous active high reset           
    output reg [WIDTH-1:0] S, // Final sum or result 
    output reg carry          // Final carry out           
);

    wire [WIDTH-1:0] P;
    wire [WIDTH-1:0] G;
    reg [WIDTH:0] C;

    wire [WIDTH-1:0] S1;
    wire carry1;

    // Generate (G) and Propagate (P) 
    genvar i;
    generate
        for (i = 0; i < WIDTH; i = i + 1) begin
            assign P[i] = A[i] ^ B[i];   
            assign G[i] = A[i] & B[i];   
        end
    endgenerate

    // Carry Calculation:
    generate
        for (i = 0; i < WIDTH; i = i + 1) begin
            always @(posedge clk) begin
                if (reset) begin
                    C <= 0; 
                end else begin
                    C[0] <= Cin;
                    C[i+1] <= G[i] | (P[i] & C[i]);
                end
            end
        end
    endgenerate

    // Final sum
    generate
        for (i = 0; i < WIDTH; i = i + 1) begin
            assign S1[i] = P[i] ^ C[i]; 
        end
    endgenerate

    // Final sum
    assign carry1 = C[WIDTH-1];

    always @(posedge clk) begin
        if (reset) begin
            S <= 0; 
            carry <= 0;   
        end else begin
            S <= S1; 
            carry <= carry1;
        end 
    end

endmodule 

module dff #(parameter WIDTH = 1) (
    input clk,               // clk -> Synchronous to posedge of clk 
    input reset,             // reset -> Synchronous active high reset
    input [WIDTH-1:0] D,     // D -> Data signal 
    output reg [WIDTH-1:0] Q // Q -> Output signal 
);
    always @(posedge clk) begin
        if (reset)
            Q <= {WIDTH{1'b0}};
        else
            Q <= D;
    end
endmodule

