module axi_tap #(
    parameter ADDR_WIDTH = 32, // Width of AXI4-Lite Address
    parameter DATA_WIDTH = 32, // Width of AXI4-Lite Data
    parameter TIMEOUT_THRESHOLD = 1000  // Timeout threshold in cycles (configurable)
)(
    // Global Ports
    input           clk_i,
    input           rst_i,
    input           timeout_threshold_i, // New port for timeout threshold

    // Transaction Status
    output reg timeout_flag_o; // New output for timeout flag

    // Global Inputs
    input           inport_awvalid_i,
    input           inport_arvalid_i,
    input           inport_wvalid_i,

    // Master Write Address Channel (AW)
    input           inport_awvalid_q,
    input  [ADDR_WIDTH-1:0]   inport_awaddr_i,
    output          inport_awready_o,
    input  [DATA_WIDTH-1:0]   inport_wdata_i,
    input  [3:0]    inport_wstrb_i,
    output          inport_wready_o,
    input           inport_bvalid_i,
    output [1:0]    inport_bresp_i,
    output          inport_bready_o,

    // Master Read Address Channel (AR)
    input           inport_arvalid_i,
    input  [ADDR_WIDTH-1:0]   inport_araddr_i,
    output          inport_arready_o,
    output [DATA_WIDTH-1:0]   inport_rdata_o,
    output [1:0]    inport_rresp_o,

    // Peripheral 0 interface
    input           inport_peripheral0_awvalid_i,
    output          inport_peripheral0_awready_o,
    output [ADDR_WIDTH-1:0]   inport_peripheral0_awaddr_i,
    output          inport_peripheral0_wvalid_o,
    output [DATA_WIDTH-1:0]   inport_peripheral0_wdata_i,
    output [3:0]    inport_peripheral0_wstrb_i,
    input           inport_peripheral0_bvalid_i,
    output          inport_peripheral0_bready_o,
    output [1:0]    inport_peripheral0_rresp_i,
    input           inport_peripheral0_rvalid_i,
    output          inport_peripheral0_rdata_i,
    output          inport_peripheral0_rready_o

    // Transaction Status
    output reg timeout_flag_o; // New output for timeout flag

    //-----------------------------------------------------------------
    // AXI: Read
    //-----------------------------------------------------------------
    reg [3:0]              read_pending_q;
    reg [3:0]              read_pending_r;
    reg [`ADDR_SEL_W-1:0]  read_port_q;
    reg [`ADDR_SEL_W-1:0]  read_port_r;

    always @*
    begin
        read_pending_r = read_pending_q;

        if (read_incr_w && !read_decr_w)
            read_pending_r = read_pending_r + 4'd1;
        else if (!read_incr_w && read_decr_w)
            read_pending_r = read_pending_r - 4'd1;
    end

    always @ (posedge clk_i )
    begin
        if (rst_i)
            read_pending_q <= 4'b0;
        else
            read_pending_q <= read_pending_r;

        // Read command accepted
        if (inport_araddr_i & `PERIPH0_MASK) == `PERIPH0_ADDR && inport_arvalid_i && inport_arready_o)
            read_port_q <= read_port_r;

        assign outport_arvalid_o = inport_arvalid_i & read_accept_w & (read_port_r == `ADDR_SEL_W'd0);
        assign outport_araddr_o  = inport_araddr_i;
        assign outport_rready_o  = inport_rready_i;

        assign outport_peripheral0_arvalid_o = inport_arvalid_i & read_accept_w & (read_port_r == `ADDR_SEL_W'd1);
        assign outport_peripheral0_araddr_o  = inport_araddr_i;
        assign outport_peripheral0_rready_o  = inport_rready_i;

        // Read timeout detection
        if (read_pending_q > timeout_threshold_i)
            timeout_flag_o = 1'b1; // Set timeout flag if threshold exceeded
        else
            timeout_flag_o = 1'b0;
    end

    //-------------------------------------------------------------
    // Write Request
    //-------------------------------------------------------------
    reg awvalid_q;
    reg wvalid_q;

    wire wr_cmd_accepted_w  = (inport_awvalid_i && inport_awready_o) || awvalid_q;
    wire wr_data_accepted_w = (inport_wvalid_i  && inport_wready_o)  || wvalid_q;

    always @ (posedge clk_i )
    begin
        if (rst_i)
            awvalid_q <= 1'b0;
        else if (inport_awvalid_i && inport_awready_o && (!wr_data_accepted_w))
            awvalid_q <= 1'b1;
        else if (wr_data_accepted_w)
            awvalid_q <= 1'b0;

        // Write timeout detection
        if (inport_awvalid_q && inport_awready_o && (!wvalid_q))
            timeout_flag_o = 1'b1; // Set timeout flag if write command is valid but data is not ready
        else
            timeout_flag_o = 1'b0;

        // Write command accepted
        if (inport_awvalid_i && inport_awready_o)
            write_port_q <= write_port_r;

        assign outport_awvalid_o = inport_awvalid_i & ~awvalid_q & write_accept_w & (write_port_r == `ADDR_SEL_W'd0);
        assign outport_awaddr_o  = inport_awaddr_i;
        assign outport_wvalid_o  = inport_wvalid_i & ~wvalid_q & (inport_awvalid_i || awvalid_q) & (write_port_r == `ADDR_SEL_W'd0);
        assign outport_wdata_o   = inport_wdata_i;
        assign outport_wstrb_o   = inport_wstrb_i;
        assign outport_bready_o  = inport_bready_i;

        // Write timeout detection
        if (inport_awvalid_q && inport_awready_o && (!wvalid_q))
            timeout_flag_o = 1'b1; // Set timeout flag if write command is valid but data is not ready
        else
            timeout_flag_o = 1'b0;

        assign inport_wready_o  = write_accept_w & ~wvalid_q & inport_wready_r;
    end

    // Transaction Error Handling (simplified example)
    // This could be expanded to include retry logic, logging, or error handling mechanisms
    always @*
    begin
        if (timeout_flag_o)
            // Handle timeout, e.g., log error, retry transaction, or abort
            // Placeholder for error handling logic
            // For example: log_error("Transaction timeout detected");
        end
    end

    //-----------------------------------------------------------------
    // AXI: Write
    //-----------------------------------------------------------------
    reg [3:0]              write_pending_q;
    reg [3:0]              write_pending_r;
    reg [`ADDR_SEL_W-1:0]  write_port_q;
    reg [`ADDR_SEL_W-1:0]  write_port_r;

    always @*
    begin
        if (inport_awvalid_i & ~awvalid_q)
            write_port_r = `ADDR_SEL_W'b0;
            if ((inport_awaddr_i & `PERIPH0_MASK) == `PERIPH0_ADDR) write_port_r = `ADDR_SEL_W'd1;
        else
            write_port_r = write_port_q;
    end

    wire write_incr_w;
    wire write_decr_w;

    always @ (posedge clk_i )
    begin
        if (rst_i)
            write_pending_q <= 4'b0;
        else
            write_pending_q <= write_pending_r;

        // Write command accepted
        if (inport_awvalid_i && inport_awready_o)
            write_port_q <= write_port_r;

        assign outport_awvalid_o = inport_awvalid_i & ~awvalid_q & write_accept_w & (write_port_r == `ADDR_SEL_W'd0);
        assign outport_awaddr_o  = inport_awaddr_i;
        assign outport_wvalid_o  = inport_wvalid_i & ~wvalid_q & (inport_awvalid_i || awvalid_q) & (write_port_r == `ADDR_SEL_W'd0);
        assign outport_wdata_o   = inport_wdata_i;
        assign outport_wstrb_o   = inport_wstrb_i;
        assign outport_bready_o  = inport_bready_i;

        // Write timeout detection
        if (inport_awvalid_i && inport_awready_o && (!wvalid_q))
            timeout_flag_o = 1'b1; // Set timeout flag if write command is valid but data is not ready
        else
            timeout_flag_o = 1'b0;

        assign inport_wready_o  = write_accept_w & ~wvalid_q & inport_wready_r;
    end

endmodule

output.rtl/axis_image_border_gen.sv:
`timescale 1ps / 1ps

module axis_image_border_gen #(
    parameter IMG_WIDTH  = 336,               // Image width (X resolution)
    parameter IMG_HEIGHT = 256,              // Image height (Y resolution)
    parameter BORDER_COLOR = 16'hFFFF,       // Border pixel value
    parameter DATA_MASK    = 16'h0000        // Mask for input pixels
)(
    input  wire            clk,              // AXI clock
    input  wire            resetn,           // Active-low reset

    // AXI Stream input interface
    input  wire [15:0]     s_axis_tdata,     // Input stream data
    input  wire            s_axis_tvalid,    // Input data valid
    output wire            s_axis_tready,    // Output ready
    output wire            s_axis_tlast,     // Input last signal
    input  wire            s_axis_tuser,     // Frame start signal

    // AXI Stream output interface
    output wire [15:0]     m_axis_tdata,     // Output stream data
    output wire            m_axis_tvalid,    // Output data valid
    input  wire            m_axis_tready,    // Input ready
    output wire            m_axis_tlast,     // Output last signal
    output wire            m_axis_tuser      // Frame start signal
);

   // Add state definitions

    // State and Counter Registers
    reg [2:0] state, next_state;
    reg [15:0] x_count, y_count;
    reg border_valid;


    // Internal Control Signals
    wire is_top_row     = (y_count == 16'd0);
    wire is_bottom_row  = (y_count == IMG_HEIGHT + 1);
    wire is_left_border  = (x_count == 16'd0);
    wire is_right_border = (x_count == IMG_WIDTH + 1);
    wire is_border_pixel = (is_top_row || is_bottom_row || is_left_border || is_right_border);

   // Add logic for AXIS output signals

    // FSM and Counter Logic
    always @(posedge clk or negedge resetn) begin
        if (!resetn) begin
            state <= ST_IDLE;
            x_count <= 0;
            y_count <= 0;
            border_valid <= 0;
            m_axis_tuser <= 0;
        end else begin
            state <= next_state;
        end
    end

    // Define states
    localparam ST_IDLE = 3'b000;
    localparam ST_ROW_FIRST = 3'b001;
    localparam ST_PROCESS_ROW = 3'b010;
    localparam ST_BORDER_ROW = 3'b011;
    localparam ST_ROW_LAST = 3'b100;

    // FSM logic
    always @(posedge clk, negedge resetn) begin
        case (state)
            ST_IDLE:
                if (s_axis_tuser) begin
                    state <= ST_ROW_FIRST;
                    x_count <= 16'd0;
                end
            ST_ROW_FIRST:
                if (s_axis_tvalid && !s_axis_tlast) begin
                    if (x_count == 0) begin
                        state <= ST_PROCESS_ROW;
                        y_count <= y_count + 1;
                    end
                    x_count <= x_count + 1;
                end else if (s_axis_tlast) begin
                    state <= ST_ROW_LAST;
                    border_valid <= 1;
                    x_count <= 0;
                end
            ST_PROCESS_ROW:
                if (s_axis_tvalid && !s_axis_tlast) begin
                    if (x_count == IMG_WIDTH - 1) begin
                        state <= ST_BORDER_ROW;
                    end
                    if (is_border_pixel) begin
                        m_axis_tdata <= BORDER_COLOR;
                    end else begin
                        m_axis_tdata <= s_axis_tdata;
                    end
                    x_count <= x_count + 1;
                end else if (s_axis_tlast) begin
                    state <= ST_ROW_LAST;
                    border_valid <= 0;
                    x_count <= 0;
                end
            ST_BORDER_ROW:
                if (s_axis_tvalid && !s_axis_tlast) begin
                    if (y_count == IMG_HEIGHT - 1) begin
                        state <= ST_ROW_LAST;
                        border_valid <= 1;
                        y_count <= y_count + 1;
                    end
                    if (is_border_pixel) begin
                        m_axis_tdata <= BORDER_COLOR;
                    end else begin
                        m_axis_tdata <= s_axis_tdata;
                    end
                end else if (s_axis_tlast) begin
                    state <= ST_ROW_LAST;
                    border_valid <= 0;
                    y_count <= 0;
                end
            ST_ROW_LAST:
                m_axis_tuser <= 1;
                next_state <= ST_IDLE;
                border_valid <= 0;
                y_count <= 0;
                x_count <= 0;
        end
    end

    // Handle AXI Stream protocol signals (`tvalid`, `tready`).

endmodule

output.rtl/axis_joiner.sv:
module axis_joiner (
    input clk,
    input rst,
    input s_axis_tdata_1,
    input s_axis_tvalid_1,
    output reg s_axis_tready_1,
    input s_axis_tlast_1,
    input s_axis_tdata_2,
    input s_axis_tvalid_2,
    output reg s_axis_tready_2,
    input s_axis_tlast_2,
    input s_axis_tdata_3,
    input s_axis_tvalid_3,
    output reg s_axis_tready_3,
    output reg m_axis_tdata,
    output reg m_axis_tvalid,
    output reg m_axis_tready,
    output reg m_axis_tlast,
    output reg [2:0] m_axis_tuser,
    output reg busy
);

    reg [7:0] temp_data;
    reg [1:0] state, next_state;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            state <= 2'b00;
            temp_data <= 8'b0;
            m_axis_tready <= 1'b0;
            m_axis_tvalid <= 1'b0;
            m_axis_tdata <= 8'b0;
            m_axis_tlast <= 1'b0;
            m_axis_tuser <= 3'b0;
            busy <= 1'b0;
        end else begin
            case (state)
                2'b00: begin
                    if (s_axis_tvalid_1) begin
                        state <= 2'b01;
                        temp_data <= s_axis_tdata_1;
                    end else if (s_axis_tvalid_2 && !s_axis_tvalid_1) begin
                        state <= 2'b02;
                        temp_data <= s_axis_tdata_2;
                    end else if (s_axis_tvalid_3 && !s_axis_tvalid_1 && !s_axis_tvalid_2) begin
                        state <= 2'b03;
                        temp_data <= s_axis_tdata_3;
                    end
                end
                2'b01: begin
                    if (s_axis_tlast_1) begin
                        state <= 2'b00;
                        m_axis_tdata <= temp_data;
                        m_axis_tvalid <= 1'b1;
                        m_axis_tready <= 1'b0;
                        m_axis_tlast <= 1'b1;
                        m_axis_tuser <= 3'b1;
                        busy <= 1'b1;
                    end
                end
                2'b02: begin
                    if (s_axis_tlast_2) begin
                        state <= 2'b00;
                        m_axis_tdata <= temp_data;
                        m_axis_tvalid <= 1'b1;
                        m_axis_tready <= 1'b0;
                        m_axis_tlast <= 1'b1;
                        m_axis_tuser <= 3'b2;
                        busy <= 1'b1;
                    end
                end
                2'b03: begin
                    if (s_axis_tlast_3) begin
                        state <= 2'b00;
                        m_axis_tdata <= temp_data;
                        m_axis_tvalid <= 1'b1;
                        m_axis_tready <= 1'b0;
                        m_axis_tlast <= 1'b1;
                        m_axis_tuser <= 3'b3;
                        busy <= 1'b1;
                    end
                end
                default: next_state <= 2'b00;
            endcase
        end
    end

    assign m_axis_tdata = (state == 2'b01) ? temp_data : 8'b0;
    assign m_axis_tvalid = (state == 2'b01) ? 1'b1 : 1'b0;
    assign m_axis_tready = (state == 2'b01) ? 1'b1 : 1'b0;
    assign m_axis_tlast = (state == 2'b01) ? 1'b1 : 1'b0;
    assign m_axis_tuser = (state == 2'b01) ? 3'b1 : (state == 2'b02) ? 3'b2 : (state == 2'b03) ? 3'b3 : 3'b0;

    always @(posedge clk) begin
        if (rst) begin
            next_state <= 2'b00;
        end else begin
            next_state <= state;
        end
    end

endmodule

output.rtl/axis_mux.sv:
`timescale 1ns/1ps

module axis_mux #(
  parameter integer C_AXIS_DATA_WIDTH = 32,
  parameter integer C_AXIS_TUSER_WIDTH = 4,
  parameter integer C_AXIS_TID_WIDTH   = 2,
  parameter integer C_AXIS_TDEST_WIDTH = 2,
  parameter integer NUM_INPUTS         = 4
)(
  input  wire                                   aclk,
  input  wire                                   aresetn,
  input  wire [$clog2(NUM_INPUTS)-1:0]          sel,
  input  wire [NUM_INPUTS-1:0]                  s_axis_tvalid,
  output wire [NUM_INPUTS-1:0]                  s_axis_tready,
  input  wire [NUM_INPUTS*C_AXIS_DATA_WIDTH-1:0]   s_axis_tdata,
  input  wire [NUM_INPUTS*C_AXIS_DATA_WIDTH/8-1:0] s_axis_tkeep,
  input  wire [NUM_INPUTS-1:0]                  s_axis_tlast,
  input  wire [NUM_INPUTS*C_AXIS_TID_WIDTH-1:0] s_axis_tid,
  input  wire [NUM_INPUTS*C_AXIS_TDEST_WIDTH-1:0] s_axis_tdest,
  input  wire [NUM_INPUTS*C_AXIS_TUSER_WIDTH-1:0] s_axis_tuser,
  output wire                                   m_axis_tvalid,
  input  wire                                   m_axis_tready,
  output wire [C_AXIS_DATA_WIDTH-1:0]           m_axis_tdata,
  output wire [C_AXIS_DATA_WIDTH/8-1:0]         m_axis_tkeep,
  output wire                                   m_axis_tlast,
  output wire [C_AXIS_TID_WIDTH-1:0]            m_axis_tid,
  output wire [C_AXIS_TDEST_WIDTH-1:0]          m_axis_tdest,
  output wire [C_AXIS_TUSER_WIDTH-1:0]          m_axis_tuser
);

  // Internal signals
  reg [$clog2(NUM_INPUTS)-1:0] sel_reg;
  reg                      frame_reg;
  reg [NUM_INPUTS-1:0] ready_mask_reg;

  // Internal data and keep signals
  reg [C_AXIS_DATA_WIDTH-1:0] axis_tdata_int;
  reg [C_AXIS_DATA_WIDTH/8-1:0] axis_tkeep_int;
  reg                            axis_tlast_int;
  reg                            axis_tvalid_int;

  // Temporary storage for flow control
  reg [NUM_INPUTS-1:0] temp_tdata [NUM_INPUTS-1:0];
  reg [NUM_INPUTS-1:0] temp_tkeep [NUM_INPUTS-1:0];

  // Selection logic
  always @(posedge aclk) begin
    if (aresetn) begin
      sel_reg <= 0;
      temp_tdata <= 0;
      temp_tkeep <= 0;
      ready_mask_reg <= 0;
    end else begin
      sel_reg <= sel;
      temp_tdata <= s_axis_tvalid[sel] & s_axis_tdata;
      temp_tkeep <= s_axis_tkeep[sel];
      ready_mask_reg <= s_axis_tready[sel];
    end
  end

  // Output logic
  always @(posedge aclk) begin
    if (aresetn) begin
      m_axis_tvalid <= 0;
      m_axis_tdata <= 0;
      m_axis_tkeep <= 0;
      m_axis_tlast <= 0;
      m_axis_tid <= 0;
      m_axis_tdest <= 0;
      m_axis_tuser <= 0;
    end else begin
      m_axis_tvalid <= axis_tvalid_int & ready_mask_reg;
      m_axis_tdata <= axis_tdata_int;
      m_axis_tkeep <= axis_tkeep_int;
      m_axis_tlast <= axis_tlast_int;
      m_axis_tid <= axis_tid[NUM_INPUTS*C_AXIS_TID_WIDTH-NUM_INPUTS+sel];
      m_axis_tdest <= axis_tdest[NUM_INPUTS*C_AXIS_TDEST_WIDTH-NUM_INPUTS+sel];
      m_axis_tuser <= s_axis_tuser[NUM_INPUTS*C_AXIS_TUSER_WIDTH-NUM_INPUTS+sel];
    end
  end

  // Handling of selection
  always @(posedge aclk) begin
    if (sel_reg == sel) begin
      axis_tvalid_int <= s_axis_tvalid[sel];
      axis_tdata_int <= s_axis_tdata[NUM_INPUTS*C_AXIS_DATA_WIDTH-NUM_INPUTS+sel:C_AXIS_DATA_WIDTH-1];
      axis_tkeep_int <= s_axis_tkeep[sel];
      temp_tdata <= s_axis_tdata[NUM_INPUTS*C_AXIS_DATA_WIDTH-NUM_INPUTS+sel*C_AXIS_DATA_WIDTH-1:NUM_INPUTS*C_AXIS_DATA_WIDTH];
      temp_tkeep <= s_axis_tkeep[sel];
      ready_mask_reg <= s_axis_tready[sel];
    end else begin
      m_axis_tvalid <= 0;
      m_axis_tdata <= 0;
      m_axis_tkeep <= 0;
    end
  end

  // Flow control logic
  always @(posedge aclk) begin
    if (sel_reg == sel) begin
      if (ready_mask_reg) begin
        axis_tlast_int <= s_axis_tlast[sel];
        axis_tvalid_int <= (axis_tlast_int | axis_tvalid_int);
      end else begin
        axis_tvalid_int <= 0;
      end
    end
  end

