library IEEE;
use IEEE.STD_LOGIC_1164.ALL;
use IEEE.NUMERIC_STD.ALL;

entity bcd_to_excess_3 is
    Port (
        bcd : in STD_LOGIC_VECTOR(3 downto 0);
        excess3 : out STD_LOGIC_VECTOR(3 downto 0);
        error : out STD_LOGIC
    );
end bcd_to_excess_3;

architecture Behavioral of bcd_to_excess_3 is
begin
    process(bcd)
    begin
        if bcd >= "1010" and bcd <= "1011" then
            excess3 <= "0110";
            error <= '0';
        else
            excess3 <= "0011" + "0000";
            error <= '1';
        end if;
    end process;
end Behavioral;

input.rtl/bcd_to_excess_3.sv:
`timescale 1ns / 1ps
module bcd_to_excess_3(
    input [3:0] bcd,          // 4-bit BCD input
    output reg [3:0] excess3, // 4-bit Excess-3 output
    output reg error          // Error flag to indicate invalid input
);

// The always block triggers on any change to the BCD input.
always @(bcd)
begin
    error = 1'b0; 
    case(bcd)
        4'b0000: excess3 = 4'b0011;  
        4'b0001: excess3 = 4'b0100;  
        4'b0010: excess3 = 4'b0101;  
        4'b0011: excess3 = 4'b0110;  
        4'b0100: excess3 = 4'b0111;  
        4'b0101: excess3 = 4'b1000;  
        4'b0110: excess3 = 4'b1001;  
        4'b0111: excess3 = 4'b1010;  
        4'b1000: excess3 = 4'b1011;  
        4'b1001: excess3 = 4'b1100;  
        default: begin
            excess3 = 4'b0000;   // Set output to 0 on invalid input.
            error = 1'b1;        // Set error flag to 1 to indicate an invalid input was received.
        end
    endcase
end
