module bus_arbiter (
    input wire reset,
    input wire clk,
    input wire req1,
    input wire req2,
    output reg grant1,
    output reg grant2
);
    // State encoding using localparam
    localparam IDLE    = 3'b000,
               GRANT_1 = 3'b001,
               GRANT_2 = 3'b010,
               CLEAR   = 3'b011;

    // State registers
    reg [2:0] state;
    reg [2:0] next_state;

    // Sequential logic for state transition
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            state <= IDLE;
            grant1 <= 1'b0;
            grant2 <= 1'b0;
        end else begin
            state <= next_state;
        end
    end

    // Combinational logic for next state
    always @(*) begin
        // Default assignments
        next_state = state;

        case (state)
            IDLE:
                if (req1) begin
                    next_state = GRANT_1;
                end
                else if (req2) begin
                    next_state = GRANT_2;
                end
                else begin
                    next_state = IDLE;
                end
                break;
            GRANT_1:
                if (req2) begin
                    next_state = GRANT_2;
                end
                else begin
                    next_state = IDLE;
                end
                break;
            GRANT_2:
                if (req1) begin
                    next_state = GRANT_1;
                end
                else begin
                    next_state = CLEAR;
                end
                break;
            CLEAR:
                if (req1) begin
                    next_state = IDLE;
                end
                else if (req2) begin
                    next_state = GRANT_2;
                end
                else begin
                    next_state = IDLE;
                end
                break;
        endcase
    end

    // Output logic
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            grant1 <= 1'b0;
            grant2 <= 1'b0;
        end else begin
            case (next_state)
                GRANT_1:
                    grant1 <= 1'b1;
                    grant2 <= 1'b0;
                GRANT_2:
                    grant1 <= 1'b0;
                    grant2 <= 1'b1;
                CLEAR:
                    grant1 <= 1'b0;
                    grant2 <= 1'b0;
            endcase
        end
    end

endmodule

