        end
        MASTER1_PRI: begin
            if (req2)
                next_state = GRANT_2; // Grant Master 2 if req2 is asserted
            else if (req1)
                next_state = GRANT_1; // Grant Master 1 if only req1 is asserted
            else
                next_state = IDLE; // No requests, transition to IDLE
        end
        CLEAR: begin
            if (req2)
                next_state = GRANT_2;
            else if (req1)
                next_state = GRANT_1;
            else
                next_state = IDLE; // Default to IDLE if no requests
        end
        default: next_state = IDLE;
    endcase
end

// Output Logic
always @(posedge clk or posedge reset) begin
    if (reset) begin
        grant1 <= 1'b0;
        grant2 <= 1'b0;
    end else begin
        case (next_state)
            IDLE: begin
                grant1 <= 1'b0;
                grant2 <= 1'b0;
            end
            GRANT_1: begin
                grant1 <= 1'b1;
                grant2 <= 1'b0;
            end
            GRANT_2: begin
                grant1 <= 1'b0;
                grant2 <= 1'b1;
            end
            MASTER1_PRI: begin
                grant1 <= 1'b0; // During this state, neither master is granted
                grant2 <= 1'b0;
            end
            CLEAR: begin
                grant1 <= 1'b0;
                grant2 <= 1'b0;
            end
        endcase
    end
end

endmodule

output.rtl/pseudo_lru_nmru_policy.sv:
module pseudo_lru_nmru_policy #(
    NWAYS = 4,
    NINDEXES = 32
) (
    input clock,
    input reset,
    input [$clog2(NINDEXES)-1:0] index,
    input [$clog2(NWAYS)-1:0] way_select,
    input access,
    input hit,
    output reg [$clog2(NWAYS)-1:0] way_replace
);

reg [NWAYS-1:0] recency [NINDEXES-1:0];

integer reset_counter;
always_ff @ (posedge clock or posedge reset) begin
    if (reset) begin
        for (reset_counter = 0; reset_counter < NINDEXES; reset_counter = reset_counter + 1) begin
            recency[reset_counter] <= {NWAYS{1'b0}};
        end
    end else begin
        if (access) begin
            if (hit) begin
                recency[index] <= 1'b1;
            end else begin
                recency[index] <= {NWAYS{1'b0}};
            end

            if (recency[index].count() == 0) begin
                way_replace <= way_select;
                recency[index] <= {NWAYS{1'b1}};
                for (int j = 0; j < NWAYS; j = j + 1) begin
                    recency[index][j] <= 1'b0;
                end
            end else if (recency[index].count() > 1) begin
                // Implement NMRU policy: Select the way with the smallest index
                int smallest_index = NINDEXES - 1;
                for (int j = 0; j < NWAYS; j = j + 1) begin
                    if (recency[index][j] == 1'b1 && smallest_index > j) begin
                        smallest_index = j;
                    end
                end
                way_replace <= way_select[smallest_index];
                recency[index] <= {recency[index][:smallest_index], recency[index][smallest_index+1:NWAYS-1], 1'b1};
            end
        end
    end
end

endmodule : pseudo_lru_nmru_policy

output.rtl/lru_counter_policy.sv:
module lru_counter_policy #(
    parameter NWAYS = 4,
    parameter NINDEXES = 32
)(
    input clock,
    input reset,
    input [$clog2(NI) - 1:0] index,
    input [$clog2(NW) - 1:0] way_select,
    input access,
    input hit,
    output [$clog2(NW) - 1:0] way_replace
);

    reg [(NWAYS * $clog2(NWAYS))-1:0] recency [NI-1:0];

    wire lru_slot_found;
    wire [$clog2(NW) - 1:0] lru_slot;

    integer i, n;

    // Recency Update Logic
    always_comb begin
        if (access && hit) begin
            // Set the accessed way to NWAYS-1 (most recently used)
            recency[index][(way_select * $clog2(NWAYS)) +: $clog2(NWAYS)] = NWAYS - 1;

            // Decrement counters for all other ways
            for (n = 0; n < NWAYS; n = n + 1) begin
                if (n != way_select) begin
                    recency[index][(n * $clog2(NWAYS)) +: $clog2(NWAYS)] = recency[index][(n * $clog2(NWAYS)) +: $clog2(NWAYS)] - 1;
                end
            end
        end
    end

    // Replacement Logic
    always_comb begin
        // Find the LRU slot for replacement
        lru_slot_found = 1'b0;
        lru_slot = {NWAYS{1'b0}};
        for (n = 0; n < NWAYS; n = n + 1) begin
            if (recency[index][(n * $clog2(NWAYS)) +: $clog2(NWAYS)] < lru_slot) begin
                lru_slot_found = 1'b1;
                lru_slot = recency[index][(n * $clog2(NWAYS)) +: $clog2(NWAYS)];
            end
        end

        // Assign the LRU way to way_replace
        way_replace = lru_slot_found ? way_select : (way_select - 1'b1);
    end

endmodule : lru_counter_policy

output.rtl/mru_counter_policy.sv:
module mru_counter_policy #(
    parameter NWAYS = 4,
    parameter NINDEXES = 32
)(
    input clock,
    input reset,
    input [$clog2(NINDEXES)-1:0] index,
    input [$clog2(NWAYS)-1:0] way_select,
    input access,
    input hit,
    output [$clog2(NWAYS)-1:0] way_replace
);

    reg [(NWAYS * $clog2(NWAYS))-1:0] recency [NINDEXES-1:0];

    wire [$clog2(NWAYS)-1:0] mru_slot;

    integer i, n;

    // Initialize the recency array on reset
    always_ff @ (posedge clock or posedge reset) begin
        if (reset) begin
            for (i = 0; i < NINDEXES; i = i + 1) begin
                for (n = 0; n < NWAYS; n = n + 1) begin
                    recency[i][(n * $clog2(NWAYS)) +: $clog2(NWAYS)] <= $clog2(NWAYS)'(n);
                end
            end
        end else begin
            if (access) begin
                // Cache hit: Update the MRU slot and decrement other counters
                mru_slot = way_select;
                for (i = 0; i < NINDEXES; i = i + 1) begin
                    for (n = 0; n < NWAYS; n = n + 1) begin
                        if (recency[i][(n * $clog2(NWAYS)) +: $clog2(NWAYS)] == (NWAYS - 1)) begin
                            recency[i][(n * $clog2(NWAYS)) +: $clog2(NWAYS)] <= $clog2(NWAYS)'(n + 1);
                        end else if (recency[i][(n * $clog2(NWAYS)) +: $clog2(NWAYS)] > (NWAYS - 1)) begin
                            recency[i][(n * $clog2(NWAYS)) +: $clog2(NWAYS)] <= recency[i][(n * $clog2(NWAYS)) +: $clog2(NWAYS)] - 1;
                        end
                    end
                end
            end
        end
    end

    // Determine the MRU slot for replacement
    always_comb begin
        mru_slot = -1;
        for (i = 0; i < NINDEXES; i = i + 1) begin
            for (n = 0; n < NWAYS; n = n + 1) begin
                if (recency[i][(n * $clog2(NWAYS)) +: $clog2(NWAYS)] == (NWAYS - 1)) begin
                    mru_slot = way_select;
                    break; // Exit the loop once the MRU slot is found
                end
            end
            if (mru_slot != -1) break; // Exit the loop if MRU slot is found
        end
    end

    // Assign the MRU slot to way_replace
    assign way_replace = mru_slot;

endmodule : mru_counter_policy

output.rtl/lfu_counter_policy.sv:
module lfu_counter_policy #(
    parameter NWAYS = 4,
    parameter NINDEXES = 32,
    parameter COUNTERW = 2
)(
    input clock,
    input reset,
    input [$clog2(NINDEXES)-1:0] index,
    input [$clog2(NWAYS)-1:0] way_select,
    input access,
    input hit,
    output [$clog2(NWAYS)-1:0] way_replace
);

    localparam int unsigned MAX_FREQUENCY = $pow(2, COUNTERW) - 1;

    // Frequency array to track next way to be replaced
    reg [(NWAYS * COUNTERW)-1:0] frequency [NINDEXES-1:0];

    integer i, n;

    // Sequential logic for reset and frequency updates
    always_ff @ (posedge clock or posedge reset) begin
        if (reset) begin
            for (i = 0; i < NINDEXES; i = i + 1) begin
                for (n = 0; n < NWAYS; n = n + 1) begin
                    frequency[i][(n * COUNTERW) +: COUNTERW] <= COUNTERW'(0);
                end
            end
        end else begin
            if (access) begin
                // Set the frequency counter of the accessed way
                integer access_way = way_select[0] * NWAYS + way_select[1];
                frequency[index][(access_way * COUNTERW) +: COUNTERW] <= frequency[index][(access_way * COUNTERW) +: COUNTERW] + 1;

                // Decrement counters of other ways if the accessed way has reached MAX_FREQUENCY
                if (frequency[index][(access_way * COUNTERW) +: COUNTERW] == MAX_FREQUENCY) begin
                    integer other_ways[NWAYS-1:0];
                    integer other_counters[NWAYS-1:0];
                    for (n = 0; n < NWAYS; n = n + 1) begin
                        other_ways[n] = n;
                        other_counters[n] = frequency[index][(other_ways[n] * COUNTERW) +: COUNTERW];
                    end
                    foreach (other_ways[n]) begin
                        frequency[index][(other_ways[n] * COUNTERW) +: COUNTERW] <= other_counters[n] - 1;
                    end
                end
            end
        end
    end

    // Logic to determine the least frequently used way
    always_comb begin
        integer lfu_way;
        lfu_way = -1;
        integer min_counter = MAX_FREQUENCY + 1;
        integer i, n;
        for (i = 0; i < NINDEXES; i = i + 1) begin
            for (n = 0; n < NWAYS; n = n + 1) begin
                if (frequency[i][(n * COUNTERW) +: COUNTERW] < min_counter) begin
                    min_counter = frequency[i][(n * COUNTERW) +: COUNTERW];
                    lfu_way = i;
                end
            end
        end
        // Select way_replace with the least frequently used way
        way_replace = lfu_way[0] * NWAYS + lfu_way[1];
    end

endmodule : lfu_counter_policy

output.rtl/pseudo_lru_tree_policy.sv:
module pseudo_lru_tree_policy #(
    parameter NWAYS = 4,
    parameter NINDEXES = 32
)(
    input clock,
    input reset,
    input [$clog2(NINDEXES)-1:0] index,
    input [$clog2(NWAYS)-1:0] way_select,
    input access,
    input hit,
    output [$clog2(NWAYS)-1:0] way_replace
);

    localparam int unsigned NBITS_TREE = NWAYS - 1;
    localparam int unsigned NBITS_INDEX = $clog2(NIXELSES);

    reg [NBITS_TREE-1:0] recency [NINDEXES-1:0];
    wire [NBITS_TREE-1:0] recency_updated;
    wire [$clog2(NWAYS)-1:0] pseudo_lru_slot;

    integer i;

    // Sequential logic for reset and recency updates
    always_ff @ (posedge clock or posedge reset) begin
        if (reset) begin
            for (i = 0; i < NINDEXES; i++) begin
                recency[i] <= NBITS_TREE'(0);
            end
        end else begin
            if (access) begin
                recency[index] <= recency_updated;
            end
        end
    end

    // Update recency array for hit
    always_comb begin
        if (hit) begin
            // Traverse the tree to mark the selected way as most recently used
            for (int i = NBITS_TREE-1; i >= 0; i = i/2) begin
                int direction = (way_select & (1 << i)) ? -1 : 1;
                int step = (way_select & (1 << (i-1))) ? -1 : 1;
                int index_update = (direction == -1) ? (i + 1) : (i - 1);
                recency[index] = recency[index] + (1 << index_update);
            end
        end
    end

    // Select the Pseudo LRU slot
    slot_select_pseudo_lru_tree #(
        .NWAYS (NWAYS)
    ) slot_select_unit (
        .array (recency[index]),
        .index (pseudo_lru_slot)
    );

    assign way_replace = pseudo_lru_slot;

endmodule : pseudo_lru_tree_policy

module slot_select_pseudo_lru_tree #(
    parameter NWAYS = 4
)(
    input [NWAYS-2:0] array,
    output logic [$clog2(NWAYS)-1:0] index
);

    localparam int unsigned MAX_DEPTH = $clog2(NWAYS);

    integer depth;
    logic [$clog2(NWAYS)-1:0] step;

    always_comb begin
        depth = MAX_DEPTH;
        step = 0;
        index = NWAYS'h0;

        while (depth > 0) begin
            if (array[step]) begin
                index = step;
                step = step + 1'b1;
            end else begin
                step = step - 1'b1;
                depth = depth - 1;
            end
        end
    end

endmodule : slot_select_pseudo_lru_tree

