    start_ff <= i_start & ~(i_sensor[0] | i_sensor[3]) & (|i_operation_sel[2:1]) & ~(i_operation_sel[1] & i_sensor[1]) & ~((i_operation_sel == 3'b100 || i_operation_sel == 3'b001) & i_sensor[2]);

    if(i_start && state_ff == IDLE) begin
        operation_sel_ff <= i_operation_sel;
        grind_delay_ff   <= i_grind_delay;
        heat_delay_ff    <= i_heat_delay;
        pour_delay_ff    <= i_pour_delay;
        bean_sel_in_ff   <= i_bean_sel;
    end

    counter_ff      <= counter_nx;
end

always_ff @(posedge clk or negedge rst_async_n) begin : reset_regs
    if(~rst_async_n) begin
        state_ff <= IDLE;
    end else begin
        state_ff <= state_nx;
    end
end

// ----------------------------------------
// - FSM update
// ----------------------------------------
always_comb begin
    case(state_ff)
        IDLE: begin
            counter_nx = 0;

            if(start_ff) begin
                if(~(|i_operation_sel[2:1])) begin
                    state_nx = HEAT;
                end else if(i_operation_sel[1]) begin
                    state_nx = BEAN_SEL;
                end else if(i_operation_sel[0]) begin
                    state_nx = POUR;
                end else begin
                    state_nx = POWDER;
                end
            end else begin
                state_nx = IDLE;
            end
        end
        BEAN_SEL: begin
            if(counter_ff >= SEL_CYCLES) begin
                counter_nx = 0;
                state_nx   = GRIND;
            end else begin
                counter_nx = counter_ff + 1'b1;
                state_nx   = BEAN_SEL;
            end
        end
        GRIND: begin
            if(counter_ff >= grind_delay_ff) begin
                counter_nx = 0;
                if(operation_sel_ff[0]) begin
                    state_nx = POWDER;
                end else begin
                    state_nx = HEAT;
                end
            end else begin
                counter_nx = counter_ff + 1'b1;
                state_nx   = GRIND;
            end
        end
        POWDER: begin
            if(counter_ff >= POWDER_CYCLES) begin
                counter_nx = 0;
                state_nx   = POUR;
            end else begin
                counter_nx = counter_ff + 1'b1;
                state_nx   = POUR;
            end
        end
        HEAT: begin
            if(counter_ff >= heat_delay_ff) begin
                counter_nx = 0;
                if(|operation_sel_ff[1:0]) begin
                    state_nx = POWDER;
                end else begin
                    state_nx = POUR;
                end
            end else begin
                counter_nx = counter_ff + 1'b1;
                state_nx   = HEAT;
            end
        end
        POUR: begin
            if(counter_ff >= pour_delay_ff) begin
                counter_nx = 0;
                state_nx   = IDLE;
            end else begin
                counter_nx = counter_ff + 1'b1;
                state_nx   = POUR;
            end
        end
        default: begin
            counter_nx = 0;
            state_nx   = IDLE;
        end
    endcase
end

// ----------------------------------------
// - Controller outputs
// ----------------------------------------
always_comb begin
    case(state_ff)
        IDLE: begin
            o_bean_sel      = {NS_BEANS{1'b0}};
            o_use_powder    = 1'b0;
            o_grind_beans   = 1'b0;
            o_heat_water    = 1'b0;
            o_pour_coffee   = 1'b0;
        end
        BEAN_SEL: begin
            o_bean_sel                      = 1'b0; // Set all bits to 0
            o_bean_sel[bean_sel_in_ff]      = 1'b1; // Only the position of bean_sel_ff should be 1
            o_grind_beans                   = 1'b0;
            o_use_powder                    = 1'b0;
            o_heat_water                    = 1'b0;
            o_pour_coffee                   = 1'b0;
        end
        GRIND: begin
            o_bean_sel      = {NS_BEANS{1'b0}};
            o_grind_beans   = 1'b1;
            o_use_powder    = 1'b0;
            o_heat_water    = 1'b0;
            o_pour_coffee   = 1'b0;
        end
        POWDER: begin
            o_bean_sel      = {NS_BEANS{1'b0}};
            o_grind_beans   = 1'b0;
            o_use_powder    = 1'b1;
            o_heat_water    = 1'b0;
            o_pour_coffee   = 1'b0;
        end
        HEAT: begin
            o_bean_sel      = {NS_BEANS{1'b0}};
            o_grind_beans   = 1'b0;
            o_use_powder    = 1'b0;
            o_heat_water    = 1'b1;
            o_pour_coffee   = 1'b0;
        end
        POUR: begin
            o_bean_sel      = {NS_BEANS{1'b0}};
            o_grind_beans   = 1'b0;
            o_use_powder    = 1'b0;
            o_heat_water    = 1'b0;
            o_pour_coffee   = 1'b1;
        end
        default: begin
            o_bean_sel      = {NS_BEANS{1'b0}};
            o_grind_beans   = 1'b0;
            o_use_powder    = 1'b0;
            o_heat_water    = 1'b0;
            o_pour_coffee   = 1'b0;
        end
    endcase
end

endmodule : coffee_machine

output.rtl/signed_comparator.sv:
module signed_unsigned_comparator #(parameter WIDTH = 5) (
    input [WIDTH-1:0] i_A,
    input [WIDTH-1:0] i_B,
    input i_enable,
    input i_mode,
    output reg o_greater,
    output reg o_less,
    output reg o_equal
);

    always_comb begin
        if (!i_enable) begin
            o_greater <= 1'b0;
            o_less <= 1'b0;
            o_equal <= 1'b0;
        end else begin
            wire signed_A = i_mode ? i_A : {WIDTH{1'b0}, i_A};
            wire signed_B = i_mode ? i_B : {WIDTH{1'b0}, i_B};

            if (signed_A > signed_B) begin
                o_greater <= 1'b1;
                o_less <= 1'b0;
                o_equal <= 1'b0;
            end else if (signed_A < signed_B) begin
                o_greater <= 1'b0;
                o_less <= 1'b1;
                o_equal <= 1'b0;
            end else begin
                o_greater <= 1'b0;
                o_less <= 1'b0;
                o_equal <= 1'b1;
            end
        end
    end
endmodule

output.rtl/complex_multiplier.sv:
module complex_multiplier (
    input clk,
    input arst_n,
    input [15:0] a_real,
    input [15:0] a_imag,
    input [15:0] b_real,
    input [15:0] b_imag,
    output [31:0] result_real,
    output [31:0] result_imag
);

    reg [31:0] temp_real, temp_imag;

    always_ff @(posedge clk or posedge arst_n) begin
        if (arst_n) begin
            temp_real <= 0;
            temp_imag <= 0;
        end else begin
            temp_real <= (a_real * b_real) - (a_imag * b_imag);
            temp_imag <= (a_real * b_imag) + (a_imag * b_real);
        end
    end

    assign result_real = temp_real;
    assign result_imag = temp_imag;

endmodule

output.rtl/compression_engine.sv:
module compression_engine (
  input   logic        clk,
  input   logic        reset,
  input   logic [23:0] num_i,
  output  logic [11:0] mantissa_o,
  output  logic [3:0]  exponent_o
);

  // --------------------------------------------------------
  // Internal wires and registers
  // --------------------------------------------------------
  logic [23:12] exp_oh;         // One-hot encoded exponent
  logic [3:0]   exp_bin;        // Binary exponent
  logic [3:0]   exponent;       // Adjusted exponent
  logic [11:0]  mantissa;       // Mantissa

  // --------------------------------------------------------
  // One-Hot Encoding of the Exponent
  // --------------------------------------------------------
  always @(num_i) begin
    exp_oh[23] = num_i[23];
    for (int i = 23; i >= 0; i--) begin
      exp_oh[i] = num_i[i] & ~|num_i[23:i+1];
    end
  end

  // Use the `onehot_to_bin` module to convert one-hot to binary exponent
  onehot_to_bin #(
    .ONE_HOT_W(12),
    .BIN_W(4)
  ) exp_oh_bin (
    .oh_vec_i(exp_oh),
    .bin_vec_o(exp_bin)
  );

  assign exponent = (|exp_oh) ? exp_bin + 4'h1 : exp_bin;

  // --------------------------------------------------------
  // Mantissa Extraction Logic
  // --------------------------------------------------------
  always @(posedge clk or posedge reset) begin
    if (reset) begin
      exponent_o <= 4'd0;
      mantissa_o <= 12'd0;
    end else begin
      case (exponent)
        4'd0: mantissa_o <= num_i[11:0];
        default: mantissa_o <= num_i[exponent - 12'd1 + 11:0];
      endcase
      exponent_o <= exponent;
    end
  end

endmodule

module onehot_to_bin #(
  parameter ONE_HOT_W = 12,  // Width of the one-hot input
  parameter BIN_W     = 5    // Width of the binary output
)(
  input   wire [ONE_HOT_W-1:0]  oh_vec_i,  // One-hot encoded input
  output  logic [BIN_W-1:0]     bin_vec_o  // Binary encoded output
);

  integer i;

  // Binary encoding of the one-hot vector
  always @(oh_vec_i) begin
    for (i = ONE_HOT_W-1; i >= 0; i--) begin
      bin_vec_o[i] = oh_vec_i[i];
    end
  end

endmodule

output.rtl/enhanced_fsm_signal_processor.v:
module enhanced_fsm_signal_processor(
    input clk,
    input rst_n,
    input enable,
    input clear,
    input ack,
    input fault,
    input [4:0] vector_1,
    input [4:0] vector_2,
    input [4:0] vector_3,
    input [4:0] vector_4,
    input [4:0] vector_5,
    input [4:0] vector_6,
    output reg o_ready,
    output reg o_error,
    output [1:0] o_fsm_status,
    output [7:0] o_vector_1,
    output [7:0] o_vector_2,
    output [7:0] o_vector_3,
    output [7:0] o_vector_4
);

    // State declaration
    typedef enum {IDLE, PROCESS, READY, FAULT} state_t;
    state_t current_state, next_state;

    // State register
    reg [1:0] state_reg = 2'b00; // Default to IDLE

    // State transition logic
    always @(posedge clk or posedge rst_n) begin
        if (rst_n) begin
            current_state <= IDLE;
            state_reg <= IDLE;
        end else begin
            current_state <= state_reg;
            case (current_state)
                IDLE: begin
                    if (!enable) begin
                        state_reg <= IDLE;
                    end else if (fault) begin
                        state_reg <= FAULT;
                    end
                end
                PROCESS: begin
                    if (fault) begin
                        state_reg <= FAULT;
                    end else begin
                        o_vector_1 <= vector_1;
                        o_vector_2 <= vector_2;
                        o_vector_3 <= vector_3;
                        o_vector_4 <= vector_4;
                        state_reg <= READY;
                    end
                end
                READY: begin
                    if (ack) begin
                        state_reg <= IDLE;
                    end else if (fault) begin
                        state_reg <= FAULT;
                    end
                end
                FAULT: begin
                    o_error <= 1;
                    if (clear && !fault) begin
                        state_reg <= IDLE;
                    end
                end
            endcase
        end
    end

    // Output logic
    always @(posedge clk) begin
        o_ready <= (current_state == READY);
        o_error <= (current_state == FAULT);
        o_fsm_status <= state_reg;
        o_vector_1 <= (current_state == PROCESS) ? {vector_1, 1'b1, vector_2, 1'b1, vector_3, 1'b1, vector_4, 1'b1} : 8'b0;
        o_vector_2 <= (current_state == PROCESS) ? {vector_1, 1'b1, vector_2, 1'b1, vector_3, 1'b1, vector_4, 1'b1} : 8'b0;
        o_vector_3 <= (current_state == PROCESS) ? {vector_1, 1'b1, vector_2, 1'b1, vector_3, 1'b1, vector_4, 1'b1} : 8'b0;
        o_vector_4 <= (current_state == PROCESS) ? {vector_1, 1'b1, vector_2, 1'b1, vector_3, 1'b1, vector_4, 1'b1} : 8'b0;
    end

endmodule

output.rtl/low_pass_filter.sv:
module low_pass_filter #(
    parameter DATA_WIDTH = 16,
    parameter COEFF_WIDTH = 16,
    parameter NUM_TAPS = 8
) (
    input clk,
    input reset,
    input [DATA_WIDTH * NUM_TAPS - 1:0] data_in,
    input valid_in,
    input [COEFF_WIDTH * NUM_TAPS - 1:0] coeffs,
    output [DATA_WIDTH + COEFF_WIDTH + log2_num_taps(NUM_TAPS) - 1:0] data_out,
    output valid_out
);

    // Internal signal breakdown

    // 2D Internal Representation
    reg [DATA_WIDTH * NUM_TAPS - 1:0] data_reg;
    reg [COEFF_WIDTH * NUM_TAPS - 1:0] coeffs_reg;

    // Convert input data and coefficients to 2D arrays
    always_comb begin
        if (valid_in) begin
            data_reg = data_in;
            coeffs_reg = coeffs;
        end else begin
            data_reg = {DATA_WIDTH{data_reg[NUM_TAPS*DATA_WIDTH-1:0]}},
            coeffs_reg = {COEFF_WIDTH{coeffs_reg[NUM_TAPS*COEFF_WIDTH-1:0]}};
        end
    end

    // Element-wise multiplication
    always_comb begin
        if (valid_in) begin
            {valid_out, data_out} = #1 {
                valid_out = 1'b1,
                data_out = sum_2d_multiply(data_reg, coeffs_reg)
            };
        end else begin
            {valid_out, data_out} = #1 {
                valid_out = valid_in,
                data_out = {DATA_WIDTH{data_out[NUM_TAPS*DATA_WIDTH-1:0]}}
            };
        end
    end

    // Helper function to perform 2D multiplication and summation
    function [DATA_WIDTH + COEFF_WIDTH + log2_num_taps(NUM_TAPS) - 1:0] sum_2d_multiply(
        input reg [DATA_WIDTH * NUM_TAPS - 1:0] data_2d,
        input reg [COEFF_WIDTH * NUM_TAPS - 1:0] coeffs_2d
    );
        reg [DATA_WIDTH + COEFF_WIDTH + log2_num_taps(NUM_TAPS) - 1:0] sum_result;

        always_comb begin
            sum_result = {
                (NUM_TAPS - 1'b1) {1'b0}, // Pad with zeros
                {
                    (NUM_TAPS - 1) {coeffs_2d[NUM_TAPS*COEF_WIDTH-1], 1},
                    (NUM_TAPS - 2) {coeffs_2d[NUM_TAPS*COEF_WIDTH-2], 1},
                    // ...
                    (1) {coeffs_2d[NUM_TAPS*COEF_WIDTH-NUM_TAPS], 1}
                }
            };

            for (int i = 0; i < NUM_TAPS; i++) begin
                sum_result = sum_result + (data_2d[i*DATA_WIDTH +: DATA_WIDTH] & coeffs_2d[i*COEF_WIDTH +: COEFF_WIDTH])
            end
        end

        return sum_result;
    endfunction

    // Calculate log2_num_taps
    function logic [log2_num_taps(NUM_TAPS) - 1:0] log2_num_taps(input logic num_taps);
        return $clog2(num_taps);
    endfunction

endmodule

output.rtl/decimator_and_peak_detector.sv:
module advanced_decimator_with_adaptive_peak_detection #(
    parameter N = 8,
    parameter DATA_WIDTH = 16,
    parameter DEC_FACTOR = 4
) (
    input clk,
    input reset,
    input valid_in,
    input [DATA_WIDTH * N - 1:0] data_in,
    output reg valid_out,
    output [DATA_WIDTH * (N / DEC_FACTOR) - 1:0] data_out,
    output [DATA_WIDTH - 1:0] peak_value
);

    reg [DATA_WIDTH - 1:0] decimated_data [N / DEC_FACTOR - 1:0];
    reg [DATA_WIDTH - 1:0] peak_reg;
    integer i;

    // Input data registering
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            decimated_data <= {DATA_WIDTH{1'b0}};
            peak_reg <= DATA_WIDTH'h0;
            valid_out <= 0;
        end else if (valid_in) begin
            for (i = 0; i < N / DEC_FACTOR; i = i + 1) begin
                decimated_data[i] <= data_in[(i * DEC_FACTOR +: DATA_WIDTH * DEC_FACTOR)];
            end
            valid_out <= 1;
        end else begin
            valid_out <= 0;
        end
    end

    // Peak detection
    always @(posedge clk) begin
        if (valid_out) begin
            peak_reg <= peak_reg;
            for (i = 0; i < N / DEC_FACTOR; i = i + 1) begin
                if (decimated_data[i] > peak_reg) begin
                    peak_reg <= decimated_data[i];
                end
            end
        end
    end

    // Output packing
    always @(posedge clk) begin
        if (valid_out) begin
            data_out <= decimated_data;
            peak_value <= peak_reg;
        end
    end

endmodule

output.rtl/sgd_linear_regression.sv:
module sgd_linear_regression #(
    parameter DATA_WIDTH = 16, 
    parameter LEARNING_RATE = 3'd1
) (
    input  logic clk,                               // Clock
    input  logic reset,                             // Asynchronous reset
    input  logic signed [DATA_WIDTH-1:0] x_in,      // Input data (x)
    input  logic signed [DATA_WIDTH-1:0] y_true,    // True output (target)
    output logic signed [DATA_WIDTH-1:0] w,     // Trained weight
    output logic signed [DATA_WIDTH-1:0] b      // Trained bias
);
    localparam NBW_PRED  = 2*DATA_WIDTH + 1;
    localparam NBW_ERROR = NBW_PRED + 1;
    localparam NBW_DELTA = 3 + NBW_ERROR + DATA_WIDTH;

    // Intermediate values
    logic signed [NBW_PRED-1:0] y_pred;  
    logic signed [NBW_ERROR-1:0] error;  
    logic signed [NBW_DELTA-1:0] delta_w; 
    logic signed [NBW_DELTA-1:0] delta_b;

    // Predicted output caculation
    always_comb begin
      y_pred = (w * x_in) + b;
    end

    // Error calculation
    always_comb begin
      error = y_true - y_pred;
    end

    // Weight and Bias updates
    always_comb begin
      delta_w = LEARNING_RATE * error * x_in;
      delta_b = LEARNING_RATE * error;
    end

    // Registers for weight and bias
    reg signed [DATA_WIDTH-1:0] w_reg;
    reg signed [DATA_WIDTH-1:0] b_reg;

    // Update registers on each clock cycle if reset is not active
    always_ff @(posedge clk) begin
      if (!reset) begin
        w_reg <= 0;
        b_reg <= 0;
      end else begin
        w_reg <= (w_reg + delta_w) >> NBW_DELTA-DATA_WIDTH;
        b_reg <= (b_reg + delta_b) >> NBW_DELTA-DATA_WIDTH;
      end
    end

    // Assign registers to outputs
    assign w = w_reg;
    assign b = b_reg;

endmodule

output.rtl/fsm_linear_reg.sv:
module fsm_linear_reg #(parameter DATA_WIDTH = 16) (
    input clk,
    input reset,
    input start,
    input logic [DATA_WIDTH-1:0] x_in,
    input logic [DATA_WIDTH-1:0] w_in,
    input logic [DATA_WIDTH-1:0] b_in,
    output logic [2*DATA_WIDTH-1:0] result1,
    output logic [DATA_WIDTH:0] result2,
    output done
);

    logic [DATA_WIDTH-1:0] temp_result1, temp_result2;
    logic [DATA_WIDTH-1:0] prev_x_in, prev_w_in, prev_b_in;

    // State declaration
    typedef enum logic [DATA_WIDTH-1:0] {IDLE, COMPUTE, DONE} state_t;
    state_t current_state, next_state;

    // State transition logic
    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            current_state <= IDLE;
            temp_result1 <= 0;
            temp_result2 <= 0;
            prev_x_in <= x_in;
            prev_w_in <= w_in;
            prev_b_in <= b_in;
        end else begin
            case (current_state)
                IDLE:
                    if (start) begin
                        next_state <= COMPUTE;
                        temp_result1 <= 0;
                        temp_result2 <= 0;
                    end
                    else begin
                        next_state <= IDLE;
                    end
                COMPUTE:
                    temp_result1 <= (w_in * x_in) >>> 1;
                    temp_result2 <= b_in + (x_in >>> 2);
                    next_state <= DONE;
                DONE:
                    done <= 1;
                    temp_result1 <= 0;
                    temp_result2 <= 0;
            endcase
            current_state <= next_state;
        end
    end

    // Output logic
    always_comb begin
        result1 <= temp_result1;
        result2 <= (temp_result2 << DATA_WIDTH-1) | prev_b_in;
    end

endmodule

input.rtl/cont_adder_top.sv:
module continuous_adder (
    input logic         clk,         // Clock signal
    input logic         reset,       // Reset signal, Active high and Synchronous
    input logic [7:0]   data_in,     // Input data stream (8-bit)
    input logic         data_valid,  // Input data valid signal
    output logic [7:0]  sum_out,     // Output the accumulated sum
    output logic        sum_ready    // Signal to indicate sum is output and accumulator is reset
);

    logic [7:0] sum_accum;          // Internal accumulator to store the running sum

    // Sequential logic for sum accumulation
    always_ff @(posedge clk) begin
        if (reset) begin
            // On reset, clear the accumulator, reset sum_out and sum_ready
            sum_accum         <= 8'd0;
            sum_ready         <= 1'b0;
        end
        else begin
            if (data_valid) begin
                // Add input data to the accumulator
                sum_accum     <= sum_accum + data_in;

                // Check if the accumulated sum is >= 100
                if (sum_accum + data_in >= 8'd100) begin
                    // Output the current sum and reset the accumulator
                    sum_out   <= sum_accum + data_in; // Output the accumulated sum
                    sum_ready <= 1'b1;                // Indicate that the sum is ready
                    sum_accum <= 8'd0;                // Reset the accumulator
                end
                else begin
                    // Continue accumulating, but no output until the sum reaches 100
                    sum_ready <= 1'b0;                // No output yet
                end
            end
        end
    end

endmodule

input.rtl/cont_adder.sv:
module cont_adder #(
    parameter DATA_WIDTH = 32,
    parameter signed THRESHOLD_VALUE_1 = 50,
    parameter signed THRESHOLD_VALUE_2 = 100,
    parameter SIGNED_INPUTS = 1,
    parameter ACCUM_MODE = 0,
    parameter WEIGHT = 1
) (
    input  logic                         clk,
    input  logic                         reset,
    input  logic signed [DATA_WIDTH-1:0] data_in,
    input  logic                         data_valid,
    input  logic [15:0]                  window_size,
    output logic signed [DATA_WIDTH-1:0] sum_out,
    output logic signed [DATA_WIDTH-1:0] avg_out,
    output logic                         threshold_1,
    output logic                         threshold_2,
    output logic                         sum_ready
);

    // Sequential Registers
    logic signed [DATA_WIDTH+1:0] sum_accum;
    logic [15:0]                  sample_count;

    // Combinational Signals
    logic signed [DATA_WIDTH-1:0] weighted_input;
    logic signed [DATA_WIDTH-1:0] new_sum;
    logic                         threshold_1_comb;
    logic                         threshold_2_comb;
    logic                         sum_ready_reg;

    // Combinational Logic
    always_comb begin
        sum_ready_reg = 0;
        weighted_input = data_in * WEIGHT;
        new_sum = sum_accum + weighted_input;

        threshold_1_comb = (new_sum >= THRESHOLD_VALUE_1) || (new_sum <= -THRESHOLD_VALUE_1);
        threshold_2_comb = (new_sum >= THRESHOLD_VALUE_2) || (new_sum <= -THRESHOLD_VALUE_2);

        if (data_valid) begin
            if (ACCUM_MODE == 0) begin
                if (threshold_1_comb || threshold_2_comb) begin
                    sum_ready_reg = 1;
                end else begin
                    sum_ready_reg = 0;
                end
            end else if (ACCUM_MODE == 1) begin
                if ((sample_count + 1) >= window_size) begin
                    sum_ready_reg = 1;
                end else begin
                    sum_ready_reg = 0;
                end
            end
        end else begin
            sum_ready_reg = 0;
        end
    end

    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            sum_accum     <= 0;
            sample_count  <= 0;
            sum_ready     <= 0;
            sum_out       <= 0;
            avg_out       <= 0;
            threshold_1   <= 0;
            threshold_2   <= 0;
        end else if (data_valid) begin
            threshold_1 <= threshold_1_comb;
            threshold_2 <= threshold_2_comb;

            if (ACCUM_MODE == 1) begin  
                sum_accum    <= sum_accum + weighted_input;
                sample_count <= sample_count + 1;
                if (sum_ready_reg) begin
                    sum_out      <= sum_accum + weighted_input;
                    avg_out      <= (sum_accum + weighted_input) / window_size;
                    sum_ready    <= 1;
                    sum_accum    <= 0;
                    sample_count <= 0;
                end else begin
                    sum_ready <= 0;
                    sum_out   <= 0;
                    avg_out   <= 0;
                end
            end else begin  
                sum_accum <= sum_accum + weighted_input;
                if (sum_ready_reg) begin
                    sum_out   <= sum_accum + weighted_input;
                    sum_ready <= 1;
                end else begin
                    sum_ready <= 0;
                    sum_out   <= 0;
                end
                avg_out <= 0; 
            end
        end else begin
            sum_ready <= 0;
        end
    end

endmodule

