  localparam EXTRA_BIT = (PARITY == 0) ? 0 : 1;
  localparam SHIFT_W   = DATA_W + EXTRA_BIT;

  // Internal regs
  reg                    state_q, state_d;
  reg  [SHIFT_W-1:0]     shift_reg_q, shift_reg_d;
  reg  [$clog2(SHIFT_W)-1:0] count_q, count_d;

  // Parity calculation
  wire parity_bit_even = ^p_data_i;   // XOR => "even"
  wire parity_bit_odd  = ~^p_data_i;  // invert XOR => "odd"

  wire parity_bit = (PARITY == 1) ? parity_bit_even :
                    (PARITY == 2) ? parity_bit_odd  :
                                    1'b0; // NONE

  // Sequential state & register updates
  always @(posedge clk or posedge reset) begin
    if (reset) begin
      state_q     <= ST_RX;
      shift_reg_q <= {SHIFT_W{1'b0}};
      count_q     <= 0;
    end else begin
      state_q     <= state_d;
      shift_reg_q <= shift_reg_d;
      count_q     <= count_d;
    end
  end

  // Next-state logic
  always @* begin
    // Default assignments
    state_d     = state_q;
    shift_reg_d = shift_reg_q;
    count_d     = count_q;

    case (state_q)

      // ST_RX: Load parallel data + parity
      ST_RX: begin
        if (p_valid_i) begin
          if (BIT_ORDER == 0) begin
            // LSB-first => store LSB in shift_reg_d[0]
            if (EXTRA_BIT == 1)
              shift_reg_d = {parity_bit, p_data_i};  // 9 bits if PARITY!=0
            else
              shift_reg_d = p_data_i;                // 8 bits if PARITY=0
          end
          else begin
            // MSB-first => store MSB in shift_reg_d[SHIFT_W-1]
            // Correctly place the parity bit in the LSB if EXTRA_BIT=1
            if (EXTRA_BIT == 1) begin
              shift_reg_d[SHIFT_W-1] = parity_bit;
              shift_reg_d[DATA_W-1:SHIFT_W-2] = p_data_i;
            end else
              shift_reg_d = p_data_i;
          end

          count_d = 0;
          state_d = ST_TX;
        end
      end

      // ST_TX: Shift bits out until SHIFT_W done
      ST_TX: begin
        // Only shift if s_ready_i & tx_en_i
        if (s_ready_i && tx_en_i) begin
          if (count_q == (SHIFT_W - 1)) begin
            // Done sending SHIFT_W bits
            state_d   = ST_RX;
            count_d   = 0;
          end
          else begin
            if (BIT_ORDER == 1) begin
              // MSB-first => shift left by 1
              shift_reg_d = shift_reg_q << 1;
              count_d     = count_q + 1;
            end else
              // LSB-first => shift right by 1
              shift_reg_d = shift_reg_q >> 1;
              count_d     = count_q + 1;
            end
          end
        end
      end

      default: begin
        state_d = ST_RX; // safe fallback
      end
    endcase
  end

  // Outputs
  assign s_valid_o = (state_q == ST_TX);

  // LSB-first => s_data_o = shift_reg_q[0]
  // MSB-first => s_data_o = shift_reg_q[SHIFT_W-1]
  assign s_data_o  = (BIT_ORDER == 0) ? shift_reg_q[0] : shift_reg_q[SHIFT_W-1];

  assign p_ready_o = (state_q == ST_RX);

endmodule

output.rtl/data_width_converter.sv:
module data_width_converter(
    input clk,
    input reset,
    input [31:0] data_in,
    input data_valid,
    output reg [127:0] o_data_out,
    output reg o_data_out_valid
);

    // Internal signals
    reg [31:0] buffer[4:0];
    reg [1:0] buffer_count = 0;
    reg [1:0] output_valid = 0;

    // State machine
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            buffer_count <= 0;
            o_data_out <= 16'h00000000;
            o_data_out_valid <= 0;
        end else if (buffer_count == 4) begin
            buffer_count <= 0;
            o_data_out <= {buffer[3], buffer[2], buffer[1], buffer[0]};
            o_data_out_valid <= 1;
        end else if (data_valid && buffer_count < 4) begin
            buffer[buffer_count] <= data_in;
            buffer_count <= buffer_count + 1;
        end
    end

endmodule

output.rtl/dbi_enc.sv:
module dbi_enc(
    input clk,
    input rst_n,
    input [39:0] data_in,
    output reg [39:0] data_out,
    output reg [1:0] dbi_cntrl
);

    reg [20:0] prev_group1, prev_group0;

    initial begin
        prev_group1 = 32'h0000_0000;
        prev_group0 = 32'h0000_0000;
    end

    always @(posedge clk or posedge rst_n) begin
        if (rst_n) begin
            data_out <= 32'h0000_0000;
            dbi_cntrl <= 2'b00;
        end else begin
            if (prev_group1 != data_in[39:20]) begin
                dbi_cntrl[1] <= (prev_group1 ^ data_in[39:20]) > 10;
                if (dbi_cntrl[1]) begin
                    data_out[39:20] <= ~data_in[39:20];
                end else begin
                    data_out[39:20] <= data_in[39:20];
                end
            end

            if (prev_group0 != data_in[19:0]) begin
                dbi_cntrl[0] <= (prev_group0 ^ data_in[19:0]) > 10;
                if (dbi_cntrl[0]) begin
                    data_out[19:0] <= ~data_in[19:0];
                end else begin
                    data_out[19:0] <= data_in[19:0];
                end
            end

            prev_group1 <= data_in[39:20];
            prev_group0 <= data_in[19:0];
        end
    end

endmodule

output.rtl/dbi_dec.sv:
module dbi_dec (
   // Inputs
   input  wire        rst_n,     // Asynchronous reset
   input  wire        clk,       // Clock
   input  wire [39:0] data_in,   // Data input before DBI decoder logic
   input  wire [1:0]  dbi_cntrl, // Indicate data inversion enabled for each group 
   // Outputs
   output wire [39:0] data_out   // Output data after DBI logic
   );

   // Internal wires for splitting and decoding
   wire [39:0] group_1, group_0;

   // Splitting the 40-bit input into two 20-bit groups
   assign group_1 = data_in[39:20];
   assign group_0 = data_in[19:0];

   // Decoding logic based on dbi_cntrl
   assign group_1 = (dbi_cntrl == 2'b00) ? group_1 : ~group_1;
   assign group_0 = (dbi_cntrl == 2'b00) ? group_0 : ~group_0;

   // Combining the decoded groups to form the output
   assign data_out = {group_1, group_0};

   // Reset logic
   always @(posedge clk or negedge rst_n) begin
      if (!rst_n) begin
         data_out <= 40'h00_0000_0000; // Reset output to all zeros
      end else begin
         data_out <= {group_1, group_0}; // Normal operation
      end
   end

endmodule

output.rtl/cvdp_copilot_decode_firstbit.sv:
module first_bit_decoder #(
    parameter INWIDTH_g = 32,
    parameter INREG_g = 1,
    parameter OUTREG_g = 1,
    parameter PLREGS_g = 1
)(
    input wire clk,
    input wire rst,
    input wire [INWIDTH_g-1:0] in_data,
    input wire in_valid,
    output reg [$clog2(INWIDTH_g)-1:0] out_first_bit,
    output reg out_found,
    output reg out_valid
);

    // Pipeline registers
    reg [$clog2(INWIDTH_g)-1:0] pipeline_stage[PLREGS_g-1:0];

    // Control signals
    reg pipeline_stages_full;

    // Internal pipeline logic
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            out_first_bit <= 0;
            out_found <= 0;
            out_valid <= 0;
            pipeline_stage <= {INWIDTH_g{0}};
            pipeline_stages_full <= 0;
        end else begin
            if (in_valid) begin
                pipeline_stage[0] <= in_data;
                pipeline_stages_full <= PLREGS_g;
            end else begin
                pipeline_stage <= pipeline_stage[PLREGS_g-1];
            end

            if (PLREGS_g == 0) begin
                pipeline_stage[PLREGS_g-1] <= in_data;
                out_first_bit <= $clog2(INWIDTH_g) - 1;
                out_found <= in_data[0] & pipeline_stage[0];
                out_valid <= in_valid & out_found;
            end else begin
                if (pipeline_stages_full) begin
                    pipeline_stage[PLREGS_g-1] <= pipeline_stage[PLREGS_g-2];
                    pipeline_stages_full <= 0;
                end

                if (in_data[0] & pipeline_stage[PLREGS_g-1]) begin
                    out_first_bit <= $clog2(INWIDTH_g) - PLREGS_g;
                    out_found <= 1;
                    out_valid <= in_valid & out_found;
                end
            end
        end
    end

    // Output logic
    always @(posedge clk) begin
        if (INREG_g) begin
            in_valid <= in_valid;
        end

        if (OUTREG_g) begin
            out_first_bit <= out_first_bit;
            out_found <= out_found;
            out_valid <= out_valid;
        end
    end

endmodule

