module apb_controller (
    input clk,
    input reset_n,
    input select_a_i,
    input select_b_i,
    input select_c_i,
    input [31:0] addr_a_i,
    input [31:0] data_a_i,
    input [31:0] addr_b_i,
    input [31:0] data_b_i,
    input [31:0] addr_c_i,
    input [31:0] data_c_i,
    input apb_pready_i,

    output apb_psel_o,
    output apb_penable_o,
    output apb_pwrite_o,
    output [31:0] apb_paddr_o,
    output [31:0] apb_pwdata_o
);

    reg [1:0] state_reg, state_next;
    reg [3:0] timeout_counter;

    // State and transition logic
    always @(posedge clk or posedge reset_n) begin
        if (reset_n) begin
            state_reg <= 2'b00; // IDLE
            timeout_counter <= 4'd0;
            apb_psel_o <= 1'b0;
            apb_penable_o <= 1'b0;
            apb_pwrite_o <= 1'b0;
            apb_paddr_o <= 0;
            apb_pwdata_o <= 0;
        end else begin
            state_next = state_reg;
            if (select_a_i) state_next = 3'b01;
            else if (select_b_i) state_next = 3'b10;
            else if (select_c_i) state_next = 3'b11;
            else state_next = 2'b00; // IDLE

            if (state_next != state_reg) begin
                state_reg <= state_next;
                case (state_next)
                    3'b01: begin
                        apb_psel_o <= 1'b1;
                        apb_pwrite_o <= 1'b1;
                        apb_paddr_o <= addr_a_i;
                        apb_pwdata_o <= data_a_i;
                    end
                    3'b10: begin
                        apb_psel_o <= 1'b1;
                        apb_pwrite_o <= 1'b1;
                        apb_paddr_o <= addr_b_i;
                        apb_pwdata_o <= data_b_i;
                    end
                    3'b11: begin
                        apb_psel_o <= 1'b1;
                        apb_pwrite_o <= 1'b1;
                        apb_paddr_o <= addr_c_i;
                        apb_pwdata_o <= data_c_i;
                    end
                    2'b00: begin
                        apb_psel_o <= 1'b0;
                        apb_penable_o <= 1'b0;
                        apb_pwrite_o <= 1'b0;
                        apb_paddr_o <= 0;
                        apb_pwdata_o <= 0;
                    end
                endcase
            end
        end
    end

    // ACCESS Phase logic
    always @(posedge clk) begin
        if (state_reg == 3'b11) begin
            if (!apb_penable_o) begin
                apb_penable_o <= 1'b1;
                timeout_counter <= 4'd0;
            end else if (apb_penable_o && !apb_pready_i) begin
                timeout_counter <= timeout_counter + 1'b1;
                if (timeout_counter >= 4'd15) begin
                    apb_penable_o <= 1'b0;
                    apb_paddr_o <= 0;
                    apb_pwdata_o <= 0;
                    timeout_counter <= 4'd0;
                    state_reg <= 2'b00; // IDLE
                end
            end
        end
    end

endmodule

output.rtl/factorial.sv:
module factorial #(parameter WIDTH = 64) (
    input clk,
    input arst_n,
    input [4:0] num_in,
    input start,
    output reg busy,
    output reg [WIDTH-1:0] fact,
    output reg done
);

    typedef enum logic [1:0] {IDLE, BUSY, DONE} state_t;
    state_t state, next_state;

    // State transition table
    // Next state | Current state | Start | Arst_n | Num_in | Busy | Done | Next state
    // ---------------------------------------------------------------------------------
    // BUSY      | IDLE           | 1     | 0      | 1      | 0    | 0    | BUSY
    // BUSY      | BUSY           | 0     | 0      | 0      | 1    | 0    | DONE
    // DONE      | IDLE           | 0     | 1      | 0      | 0    | 1    | IDLE

    // State transition logic
    always_ff @(posedge clk or posedge arst_n) begin
        case ({state, start, arst_n, num_in})
            {IDLE, 1, 0, 1'b1} : begin
                state <= BUSY;
                busy <= 1'b0;
                next_state <= BUSY;
            end
            {BUSY, 0, 0, 0'b0} : begin
                state <= DONE;
                busy <= 1'b1;
                next_state <= IDLE;
            end
            {DONE, 0, 1, 0'b0} : begin
                state <= IDLE;
                busy <= 1'b0;
                next_state <= DONE;
            end
            default : begin
                state <= IDLE;
                busy <= 1'b0;
                next_state <= IDLE;
            end
        endcase
    end

    // FSM state logic
    always @(posedge clk or posedge arst_n) begin
        if (arst_n) begin
            state <= IDLE;
            busy <= 1'b0;
            fact <= 1'b0;
            done <= 1'b0;
        end else if (state == IDLE) begin
            if (start) begin
                state <= BUSY;
                busy <= 1'b0;
                fact <= 1'b0;
                done <= 1'b0;
            end
        end else if (state == BUSY) begin
            if (num_in == 0) begin
                fact <= 1'b1; // Factorial of 0 is 1
                state <= DONE;
                busy <= 1'b0;
                done <= 1'b1;
            end else begin
                fact <= fact * num_in;
                state <= BUSY;
            end
        end else if (state == DONE) begin
            busy <= 1'b0;
            done <= 1'b0;
        end
    end

endmodule

