            prdata   <= 8'b0;
            pready   <= 1'b0;
            pslverr  <= 1'b0;
            TEMP_LOW <= 8'd30;
            TEMP_MED <= 8'd60;
            TEMP_HIGH <=8'd90;
            setup  <= 1'b0;
        end
        else
        begin
            if (psel && !penable && !setup)
            begin
                // Setup phase: Indicate the slave is not yet ready
                pready <= 1'b0;
                setup  <= 1'b1;

            end
            else if (psel && penable && setup)
            begin
                // Access phase: Perform read/write operation and indicate ready
                pready <= 1'b1; // Slave is ready for the current operation
                setup  <= 1'b0;
                if (pwrite)
                 begin
                    // Write Operation
                    case(paddr)
                          8'h0a: begin 
                                  TEMP_LOW    <= pwdata;
                                  pslverr     <= 1'b0;
                                  end
                          8'h0b: begin 
                                  TEMP_MED    <= pwdata;
                                  pslverr     <= 1'b0;
                                  end
                          8'h0c: begin
                                  TEMP_HIGH   <= pwdata;
                                  pslverr     <= 1'b0;
                                  end
                          8'h0f: begin
                                  temp_adc_in <= pwdata;
                                  pslverr     <= 1'b0;
                                  end
                          default:pslverr     <= 1'b1;
                    endcase
                end
                else 
                begin
                    // Read Operation
                    case(paddr)
                          8'h0a: begin
                                  prdata   <= TEMP_LOW ;
                                  pslverr  <= 1'b0;
                                  end
                          8'h0b: begin 
                                  prdata   <= TEMP_MED ;
                                  pslverr  <= 1'b0;
                                  end
                          8'h0c: begin
                                  prdata   <= TEMP_HIGH;
                                  pslverr  <= 1'b0;
                                  end
                          8'h0f: begin
                                  prdata   <= temp_adc_in;
                                  pslverr  <= 1'b0;
                                  end
                          default:pslverr  <= 1'b1;
                    endcase
                end
            end
            else
            begin
                // Default case: Clear ready signal when not selected
                pready <= 1'b0;
                setup  <= 1'b0;
            end
        end
    end

    // PWM control
    reg [7:0] pwm_duty_cycle;    // Duty cycle (0-255)
    reg [7:0] pwm_counter;       // Counter for PWM generation
    wire [2:0] speed_control;    //speed control bit 
    // Fan speed adjustment logic
    always @(posedge clk or posedge reset) begin
        if (reset)
        begin
            pwm_duty_cycle <= 8'd0;  // Fan off by default
        end 
        else
        begin
            case(speed_control)
              3'd1 : pwm_duty_cycle <= 8'd64;  // Low speed (25% duty cycle)
              3'd2 : pwm_duty_cycle <= 8'd128; // Medium speed (50% duty cycle)
              3'd3 : pwm_duty_cycle <= 8'd192; // High speed (75% duty cycle)
              3'd4 : pwm_duty_cycle <= 8'd255; // Full speed (100% duty cycle)
            default :  pwm_duty_cycle <= 8'd255; // Full speed (100% duty cycle)
            endcase

        end
    end

    assign speed_control = (temp_adc_in < TEMP_LOW ? 3'd1 : 
                           (temp_adc_in < TEMP_MED ? 3'd2 : 
                           (temp_adc_in < TEMP_HIGH ? 3'd3 : 3'd4)));

    // PWM generation logic
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            pwm_counter <= 8'd0;
            fan_pwm_out <= 1'b0;
        end else begin
            pwm_counter <= pwm_counter + 1;
            fan_pwm_out <= (pwm_counter < pwm_duty_cycle) ? 1'b1 : 1'b0;
        end
    end

endmodule

