                data_xtimesE_nx[line][column] = data_xtimesE_ff[line][column];
            end else begin
                data_xtimes3_nx[line][column] = data_xtimes3_ff[line][column];
                data_xtimes9_nx[line][column] = data_xtimes8[line][column] ^ data_in_ff[line][column] ^ data_xtimes2_ff[line][column];
                data_xtimesB_nx[line][column] = data_xtimes8[line][column] ^ data_xtimes2_ff[line][column] ^ data_in_ff[line][column];
                data_xtimesD_nx[line][column] = data_xtimes8[line][column] ^ data_xtimes4_ff[line][column] ^ data_in_ff[line][column];
                data_xtimesE_nx[line][column] = data_xtimes8[line][column] ^ data_xtimes4_ff[line][column] ^ data_xtimes2_ff[line][column] ^ data_in_ff[line][column];
            end
        end
    end
end

// Encryption/Decryption Output Calculation
always_comb begin : out_matrix
    if (i_encrypt) begin
        for (int line = 0; line < LINES; line++) begin
            for (int column = 0; column < COLUMNS; column++) begin
                if (line == 0) begin
                    data_out_nx[line][column] = data_xtimes2_ff[line][column] ^ data_xtimes3_ff[(line+1)%LINES][column] ^ data_in_ff[(line+2)%LINES][column] ^ data_in_ff[(line+3)%LINES][column];
                end else if (line == 1) begin
                    data_out_nx[line][column] = data_xtimes2_ff[line][column] ^ data_xtimes3_ff[(line+1)%LINES][column] ^ data_in_ff[(line+2)%LINES][column] ^ data_in_ff[(line+3)%LINES][column];
                end else if (line == 2) begin
                    data_out_nx[line][column] = data_xtimes2_ff[line][column] ^ data_xtimes3_ff[(line+1)%LINES][column] ^ data_in_ff[(line+2)%LINES][column] ^ data_in_ff[(line+3)%LINES][column];
                end else begin
                    data_out_nx[line][column] = data_xtimes2_ff[line][column] ^ data_xtimes3_ff[(line+1)%LINES][column] ^ data_in_ff[(line+2)%LINES][column] ^ data_in_ff[(line+3)%LINES][column];
                end
            end
        end
    end else begin
        for (int line = 0; line < LINES; line++) begin
            for (int column = 0; column < COLUMNS; column++) begin
                if (line == 0) begin
                    data_out_nx[line][column] = data_xtimesE_ff[line][column] ^ data_xtimesB_ff[(line+1)%LINES][column] ^ data_xtimesD_ff[(line+2)%LINES][column] ^ data_xtimes9_ff[(line+3)%LINES][column];
                end else if (line == 1) begin
                    data_out_nx[line][column] = data_xtimesE_ff[line][column] ^ data_xtimesB_ff[(line+1)%LINES][column] ^ data_xtimesD_ff[(line+2)%LINES][column] ^ data_xtimes9_ff[(line+3)%LINES][column];
                end else if (line == 2) begin
                    data_out_nx[line][column] = data_xtimesE_ff[line][column] ^ data_xtimesB_ff[(line+1)%LINES][column] ^ data_xtimesD_ff[(line+2)%LINES][column] ^ data_xtimes9_ff[(line+3)%LINES][column];
                end else begin
                    data_out_nx[line][column] = data_xtimesE_ff[line][column] ^ data_xtimesB_ff[(line+1)%LINES][column] ^ data_xtimesD_ff[(line+2)%LINES][column] ^ data_xtimes9_ff[(line+3)%LINES][column];
                end
            end
        end
    end
end

// Output Mapping
always_comb begin : out_mapping
    if (valid_ff[LATENCY]) begin
        for (int line = 0; line < LINES; line++) begin
            for (int column = 0; column < COLUMNS; column++) begin
                if (line == 0) begin
                    o_data[(NBW_DATA-(column*NBW_WORD + line*NBW_WORD*COLUMNS)-1:NBW_WORD-1] = data_out_nx[line][column] ^ key_ff[NBW_KEY-line*NBW_WORD-1:NBW_WORD];
                end else {
                    o_data[(NBW_DATA-(column*NBW_WORD + line*NBW_WORD*COLUMNS)-1:NBW_WORD-1] = data_out_nx[line][column];
                }
            end
        end
    end else begin
        o_data = 0;
    end
end

// Map Output Valid Signal
assign o_valid = valid_ff[LATENCY];

endmodule : galois_encryption

