module gmii_rx_to_axi_stream (
    input wire        gmii_rx_clk,
    input wire [7:0]  gmii_rxd,
    input wire        gmii_rx_dv,
    output wire [7:0] m_axis_tdata,
    output wire       m_axis_tvalid,
    input wire        m_axis_tready,
    output wire       m_axis_tlast
);

    // State definitions
    localparam IDLE = 2'b00,
               RECEIVING = 2'b01,
               FINISHED = 2'b10;

    // State register
    reg [2:0] state_reg = IDLE;
    // Next state logic
    always @(posedge gmii_rx_clk or negedge gmii_rx_dv) begin
        if (!gmii_rx_dv) begin
            state_reg <= IDLE;
        end else if (state_reg == IDLE) begin
            state_reg <= RECEIVING;
        end else if (state_reg == RECEIVING) begin
            if (m_axis_tready) begin
                state_reg <= FINISHED;
                m_axis_tlast <= 1'b1;
            end
        end
    end

    // Data output logic
    always @(state_reg or m_axis_tready or gmii_rxd) begin
        case (state_reg)
            IDLE: m_axis_tdata <= 8'b0;
            RECEIVING: begin
                if (m_axis_tready)
                    m_axis_tdata <= gmii_rxd;
                m_axis_tvalid <= 1'b1;
            end
            FINISHED: begin
                m_axis_tvalid <= 1'b0;
                m_axis_tlast <= 1'b1;
            end
        endcase
    end

endmodule

