                    clr_en = 0;
                    cap_en = 0;
                    delta_en = 0;
                    sum_en = 0; 
                    iteration = iteration + 0;     
                    target = target + 4'h0;              
                  end
             S3 : begin
                    clr_en = 0;
                    cap_en = 0;
                    delta_en = 0;
                    sum_en = 0;
                    iteration = iteration + 0;
                    target = t1;
                  end
             S4 : begin
                    clr_en = 0;
                    cap_en = 0;
                    delta_en = 0;
                    sum_en = 0;
                    iteration = iteration + 0;
                    target = t2;
                  end     

             S5 : begin
                    clr_en = 0;
                    cap_en = 0;
                    delta_en = 0;
                    sum_en = 0;
                    iteration = iteration + 0;
                    target = t3;
                  end  
             S6 : begin
                    clr_en = 0;
                    cap_en = 0;
                    delta_en = 0;
                    sum_en = 0;
                    iteration = iteration + 0;
                    target = t4;
                  end        
             S7 : begin
                    clr_en = 0;
                    cap_en = 0;
                    delta_en = 1;
                    sum_en = 0;
                    iteration = iteration + 0;
                    target = target + 4'h0;
                  end
             S8 : begin
                    clr_en = 0;
                    cap_en = 0;
                    delta_en = 0;
                    sum_en = 1;
                    iteration = iteration + 1;
                    target = target + 4'h0;
                  end
             S9 : begin
                    clr_en = 0;
                    cap_en = 0;
                    delta_en = 0;
                    sum_en = 0;
                    iteration = iteration + 0;
                    target = target + 4'h0;
                  end  
             S10 : begin
                    clr_en = 0;
                    cap_en = 0;
                    delta_en = 0;
                    sum_en = 0;
                    iteration = iteration + 0;
                    target = target + 4'h0;
                  end



           default : begin
                      clr_en = 0;
                      cap_en = 0;
                      delta_en = 0;
                      sum_en = 0;
                      iteration = 0;
                      target = target + 4'h0;
                     end
       endcase
   end
   assign w1 = w1_reg;
   assign w2 = w2_reg;
   assign bias = bias_reg;

endmodule

