module matrix_multiplier #(
  parameter ROW_A             = 4                                                   , // Number of rows in matrix A
  parameter COL_A             = 4                                                   , // Number of columns in matrix A
  parameter ROW_B             = 4                                                   , // Number of rows in matrix B
  parameter COL_B             = 4                                                   , // Number of columns in matrix B
  parameter INPUT_DATA_WIDTH  = 8                                                   , // Bit-width of input data
  parameter OUTPUT_DATA_WIDTH = (INPUT_DATA_WIDTH * 2) + $clog2(COL_A)                // Bit-width of output data
) (
  input  logic                                       clk      , // Clock input
  input  logic                                       srst     , // Active-high Synchronous reset
  input  logic                                       valid_in , // Indicates valid input matrices
  input  logic [ (ROW_A*COL_A*INPUT_DATA_WIDTH)-1:0] matrix_a , // Input matrix A in 1D form
  input  logic [ (ROW_B*COL_B*INPUT_DATA_WIDTH)-1:0] matrix_b , // Input matrix B in 1D form
  output logic                                       valid_out, // Indicates valid output matrix
  output logic [(ROW_A*COL_B*OUTPUT_DATA_WIDTH)-1:0] matrix_c   // Output matrix C in 1D form
);
  genvar gv1;
  genvar gv2;
  genvar gv3;

  generate
    logic [                                  COL_A:0] valid_out_reg; // Pipeline valid signal shift register
    logic [(ROW_A*COL_B*COL_A*OUTPUT_DATA_WIDTH)-1:0] mult_stage   ; // Intermediate multiplication results
    logic [(ROW_A*COL_B*COL_A*OUTPUT_DATA_WIDTH)-1:0] add_stage    ; // Accumulated addition results

    always_ff @(posedge clk)
      if (srst)
        {valid_out, valid_out_reg} <= '0;
      else
        {valid_out, valid_out_reg} <= {valid_out_reg, valid_in}; 

    for (gv1 = 0 ; gv1 < ROW_A ; gv1++) begin: row_a_gb
      for (gv2 = 0 ; gv2 < COL_B ; gv2++) begin: col_b_gb
        for (gv3 = 0 ; gv3 < COL_A ; gv3++) begin: col_a_gb
          always_ff @(posedge clk)
            if (srst)
              mult_stage[((((gv1*COL_B)+gv2)*COL_A)+gv3)*OUTPUT_DATA_WIDTH+:OUTPUT_DATA_WIDTH] <= '0; 
            else
              mult_stage[((((gv1*COL_B)+gv2)*COL_A)+gv3)*OUTPUT_DATA_WIDTH+:OUTPUT_DATA_WIDTH] <= matrix_a[((gv1*COL_A)+gv3)*INPUT_DATA_WIDTH+:INPUT_DATA_WIDTH] * matrix_b[((gv3*COL_B)+gv2)*INPUT_DATA_WIDTH+:INPUT_DATA_WIDTH]; 


          always_ff @(posedge clk)
            if (srst)
              add_stage[((((gv1*COL_B)+gv2)*COL_A)+gv3)*OUTPUT_DATA_WIDTH+:OUTPUT_DATA_WIDTH] <= '0; 
            else if (gv3 == 0)
              add_stage[((((gv1*COL_B)+gv2)*COL_A)+gv3)*OUTPUT_DATA_WIDTH+:OUTPUT_DATA_WIDTH] <= mult_stage[((((gv1*COL_B)+gv2)*COL_A)+gv3)*OUTPUT_DATA_WIDTH+:OUTPUT_DATA_WIDTH];
            else
              add_stage[((((gv1*COL_B)+gv2)*COL_A)+gv3)*OUTPUT_DATA_WIDTH+:OUTPUT_DATA_WIDTH] <= mult_stage[((((gv1*COL_B)+gv2)*COL_A)+gv3)*OUTPUT_DATA_WIDTH+:OUTPUT_DATA_WIDTH] + add_stage[((((gv1*COL_B)+gv2)*COL_A)+(gv3-1))*OUTPUT_DATA_WIDTH+:OUTPUT_DATA_WIDTH];
        end


        always_ff @(posedge clk)
          if (srst)
            matrix_c[((gv1*COL_B)+gv2)*OUTPUT_DATA_WIDTH+:OUTPUT_DATA_WIDTH] <= '0; // Reset output matrix element
          else if (valid_out_reg[COL_A])
            matrix_c[((gv1*COL_B)+gv2)*OUTPUT_DATA_WIDTH+:OUTPUT_DATA_WIDTH] <= add_stage[((((gv1*COL_B)+gv2)*COL_A)+(COL_A-1))*OUTPUT_DATA_WIDTH+:OUTPUT_DATA_WIDTH]; // Set output to the accumulated result
      end
    end

  endgenerate

endmodule

output.rtl/cvdp_copilot_mem_allocator.sv:
module cvdp_copilot_mem_allocator #(
    parameter SIZE  = 4,
    parameter ADDRW = $clog2(SIZE)
) (
    input  wire             clk,
    input  wire             reset,

    input  wire             acquire_en,    
    output wire [ADDRW-1:0] acquire_addr,      

    input  wire             release_en,
    input  wire [ADDRW-1:0] release_addr,    

    output wire             empty,
    output wire             full    
);
    reg [SIZE-1:0] free_slots, free_slots_n;
    reg [ADDRW-1:0] acquire_addr_r;
    reg empty_r, full_r;    
    wire [ADDRW-1:0] free_index;
    wire full_d;

    /* Leading zero counter instantiation */
    cvdp_leading_zero_cnt #(
        .DATA_WIDTH (DATA_WIDTH)
    ) free_slots_sel (
        .data   (free_slots_n),
        .leading_zeros  (free_index),
        .all_zeros (full_d)
    ); 

    // Memory allocation logic
    always @(posedge clk) begin
        if (reset) begin
            free_slots <= (SIZE-1:0) << 1; // Initialize all slots to free
            acquire_addr_r <= (SIZE-1:0) << 1; // Initialize acquire_addr to indicate first slot
            empty_r <= 1; // All slots are initially free
            full_r <= 0; // No slots are initially full
        end else begin
            if (acquire_en) begin
                acquire_addr_r <= free_index;
                free_slots_n <= free_slots_n ^ (acquire_addr_r); // Mark slot as allocated
                free_slots <= free_slots_n;
                empty_r <= 0; // At least one slot is now occupied
                full_r <= (SIZE == (free_slots_n & ((1 << (ADDRW-1)) - 1)) ? 1 : 0); // Check if all slots are full
            end
            if (release_en) begin
                free_slots_n <= free_slots_n ^ (release_addr); // Mark slot as free
                free_slots <= free_slots_n;
                if (free_slots_n == (SIZE-1:0) << 1) begin
                    empty_r <= 0; // No more free slots
                    full_r <= 1; // All slots are now full
                end
            end
        end
    end

endmodule

output.rtl/microcode_sequencer.sv:
module microcode_sequencer(
    input clk,
    input c_n_in,
    input c_inc_in,
    input r_en,
    input cc,
    input ien,
    input d_in[3:0],
    input instr_in[4:0],
    output reg d_out[3:0],
    output reg c_n_out,
    output reg c_inc_out,
    output reg full,
    output reg empty
);

    wire full_o, empty_o;

    // Stack Management Submodule
    logic [4:0] stack_data_out;
    logic stack_addr, full, empty;
    wire stack_data1_in, stack_data2_in;
    wire stack_reset, stack_push, stack_pop, stack_mux_sel, stack_we, stack_re;

    lifo_stack lifo_stack_inst(
        .clk(clk),
        .stack_data1_in(d_in),
        .stack_data2_in(pc_out),
        .stack_reset(stack_reset),
        .stack_push(stack_push),
        .stack_pop(stack_pop),
        .stack_mux_sel(stack_mux_sel),
        .stack_we(stack_we),
        .stack_re(stack_re),
        .stack_data_out(stack_data_out),
        .full(full_o),
        .empty(empty_o)
    );

    // Program Counter Submodule
    logic pc_out, pc_c_out;
    wire pc_mux_sel;

    program_counter program_counter_inst(
        .clk(clk),
        .pc_data_in(pc_out),
        .pc_c_in(pc_c_in),
        .inc(inc),
        .pc_mux_sel(pc_mux_sel),
        .pc_out(pc_out),
        .pc_c_out(pc_c_out)
    );

    // Arithmetic Operations Submodule
    logic a_mux_sel[1:0], b_mux_sel[1:0];
    logic aux_reg_in, reg_out;
    logic aux_reg_mux_out;
    logic fa_in, a_mux_out, b_mux_out;
    logic full_adder_cout;
    logic arith_cout, d_out;

    microcode_arithmetic microcode_arithmetic_inst(
        .clk(clk),
        .fa_in(fa_in),
        .d_in(d_in),
        .stack_data_in(stack_data_out),
        .pc_data_in(pc_out),
        .a_mux_sel(a_mux_sel),
        .b_mux_sel(b_mux_sel),
        .aux_reg_in(aux_reg_in),
        .reg_out(reg_out),
        .oen(oen),
        .rce(rce),
        .cen(cen),
        .a_mux_out(a_mux_out),
        .b_mux_out(b_mux_out),
        .arith_cout(full_adder_cout),
        .d_out(d_out)
    );

    // Instruction Decoder Submodule
    logic cen, rst, push, pop, src_sel, stack_we, stack_re, pc_mux_sel, a_mux_sel, b_mux_sel, out_ce;

    instruction_decoder instruction_decoder_inst(
        .clk(clk),
        .instr_in(instr_in),
        .cc_in(cc),
        .cen(cen),
        .instr_en(ien),
        .rst(rst),
        .push(push),
        .pop(pop),
        .src_sel(src_sel),
        .stack_we(stack_we),
        .stack_re(stack_re),
        .pc_mux_sel(pc_mux_sel),
        .a_mux_sel(a_mux_sel),
        .b_mux_sel(b_mux_sel),
        .out_ce(out_ce)
    );

    // Result Register Submodule
    logic result_register_out;

    result_register result_register_inst(
        .clk(clk),
        .data_in(d_out),
        .out_ce(out_ce),
        .data_out(result_register_out)
    );

    // Combinational logic to generate control signals
    assign c_n_out = c_n_in;
    assign c_inc_out = c_inc_in;
    assign full = full_o;
    assign empty = empty_o;

    // Instruction decoding logic
    always @(posedge clk) begin
        case(instruction_decoder_inst.instr_in)
            5'b00000: begin
                d_out = 4'b0000;
                pc_c_in = 'b0;
                rst = 1'b1;
                stack_push = 1'b1;
            end
            5'b00001: begin
                d_out = pc_out;
            end
            5'b00010: begin
                d_out = aux_reg_out;
            end
            5'b00011: begin
                d_out = d_in;
            end
            5'b00100: begin
                d_out = {d_in[3], d_in[2], d_in[1], d_in[0]} + {pc_out[3], pc_out[2], pc_out[1], pc_out[0]};
                pc_c_in = inc;
            end
            5'b01011: begin
                stack_push = 1'b1;
                pc_out = pc_out;
            end
            5'b01110: begin
                pc_out = stack_data_out;
            end
            default: begin
                d_out = 4'bX;
            end
        end
    end
endmodule

input.rtl/signed_sequential_booth_multiplier.s:
module signed_sequential_booth_multiplier #(parameter WIDTH = 8) (
    input  wire signed [WIDTH-1:0] A,
    input  wire signed [WIDTH-1:0] B,
    input  wire clk,
    input  wire rst,
    input  wire start,
    output reg  signed [2*WIDTH-1:0] result,
    output reg done
);

    // FSM states
    typedef enum logic [2:0] {
        IDLE     = 3'b000,
        ENCODE   = 3'b001, 
        PARTIAL  = 3'b010, 
        ADDITION = 3'b011, 
        DONE     = 3'b100
    } state_t;

    state_t state, next_state;

    // Registers for control and data signals
    reg signed [2*WIDTH-1:0] partial_products [0:WIDTH/2-1];
    reg signed [2*WIDTH-1:0] multiplicand;
    reg signed [WIDTH:0] booth_bits; 
    reg signed [2*WIDTH-1:0] accumulator;  
    reg [2:0] encoding_bits [0:WIDTH/2-1];
    reg [$clog2(WIDTH/2):0] addition_counter; // Counter for addition cycles
    integer i;

    // State machine: Sequential process for state transitions
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            state <= IDLE;
        end else begin
            state <= next_state;
        end
    end

    // State machine: Combinational process for next-state logic
    always @(*) begin
        case (state)
            IDLE: begin
                if (start) begin
                    next_state = ENCODE;
                end else begin
                    next_state = IDLE;
                end
            end

            ENCODE: begin
                next_state = PARTIAL;
            end

            PARTIAL: begin
                next_state = ADDITION;
            end

            ADDITION: begin
                next_state = DONE;
            end

            DONE: begin
                if (!start) begin
                    next_state = IDLE;
                end else begin
                    next_state = DONE;
                end
            end

            default: begin
                next_state = IDLE;
            end
        endcase
    end

    // Signal assignments: Perform operations based on current state
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            done <= 0;
            result <= 0;
            accumulator <= 0;
            addition_counter <= 0;
            multiplicand <= 0;
            booth_bits <= 0;
            for (i = 0; i < WIDTH/2; i = i + 1) begin
                encoding_bits[i] <= 0;
                partial_products[i] <= 0;
            end
        end else begin
            case (state)
                IDLE: begin
                    // Prepare for new computation
                    done <= 0;
                    result <= 0;
                    if (start) begin
                        multiplicand <= {{(WIDTH){A[WIDTH-1]}}, A}; // Sign-extend A
                        booth_bits <= {B, 1'b0};
                        accumulator <= 0;
                        for (i = 0; i < WIDTH/2; i = i + 1) begin
                            partial_products[i] <= 0;
                        end
                    end
                end

                ENCODE: begin
                    // Extract 3-bit Booth segments
                    for (i = 0; i < WIDTH/2; i = i + 1) begin
                        encoding_bits[i] <= booth_bits[2*i +: 3];
                    end
                end

                PARTIAL: begin
                    // Generate partial products based on Booth encoding
                    for (i = 0; i < WIDTH/2; i = i + 1) begin
                        case (encoding_bits[i])
                            3'b001, 3'b010: partial_products[i] <= (multiplicand << (2 * i));
                            3'b011:         partial_products[i] <= ((multiplicand << 1) << (2 * i));
                            3'b100:         partial_products[i] <= -((multiplicand << 1) << (2 * i));
                            3'b101, 3'b110: partial_products[i] <= -(multiplicand << (2 * i));
                            default:        partial_products[i] <= 0;
                        endcase
                    end
                end

                ADDITION: begin
                    accumulator <= 0;
                    for (i = 0; i < WIDTH/2; i = i + 1) begin
                      accumulator <= accumulator + partial_products[i];  
                    end
                end

                DONE: begin
                    // Output the result
                    result <= accumulator;
                    done <= 1;
                end
            endcase
        end
    end
endmodule

