output.rtl/pipeline_mac.sv:
module pipeline_mac #(
    parameter DWIDTH = 16,  // Bit width for multiplicand and multiplier
    parameter N      = 4    // Number of data points to accumulate over
) (
    input logic clk,
    input logic rstn,
    input logic [DWIDTH-1:0] multiplicand,
    input logic [DWIDTH-1:0] multiplier,
    input logic valid_i,
    output logic [DWIDTH_ACCUMULATOR-1:0] result,
    output logic valid_out
);

  // ----------------------------------------
  // - Local parameter definition
  // ----------------------------------------
  // Calculate the accumulator bit width to handle potential overflow
  parameter DWIDTH_ACCUMULATOR = DWIDTH * N + 1;

  // ----------------------------------------
  // - Interface Definitions
  // ----------------------------------------
  input logic clk;                                // Clock signal
  input logic rstn;                               // Active low reset signal
  input logic [DWIDTH-1:0] multiplicand;          // Input multiplicand
  input logic [DWIDTH-1:0] multiplier;            // Input multiplier
  input logic valid_i;                            // Input valid signal
  output logic [DWIDTH_ACCUMULATOR-1:0] result;   // Accumulated result output
  output logic valid_out;                         // Output valid signal, indicates when result is ready

  // ----------------------------------------
  // - Internal signals
  // ----------------------------------------
  logic [DWIDTH_ACCUMULATOR-1:0] mult_result_reg;    // Register to store intermediate multiplication result
  logic [DWIDTH_ACCUMULATOR-1:0] accumulation_reg;   // Register to store accumulated result
  logic [$clog2(N):0] counter;                       // Counter to track the number of accumulations
  logic [$clog2(N):0] counter_reg;                   // Register to hold the value of the counter
  logic count_rst, accumulator_rst;                  // Reset signals for counter and accumulator
  logic valid_out_s0,valid_out_s1,valid_out_s2;      // Intermediate Signals indicating that the valid output is ready
  logic valid_i_s1;                                  // Intermediate Signals indicating input valid signal

  // ----------------------------------------
  // - Procedural blocks
  // ----------------------------------------

  // Stage 1 of the pipeline: Perform multiplication
  always @(posedge clk or negedge rstn) begin
    if (!rstn) begin
      mult_result_reg <= 'b0;
      valid_out_s0 <= 0;
    end else if (valid_i) begin
      mult_result_reg <= (multiplicand * multiplier) >> (DWIDTH - 1);
      valid_out_s0 <= 1;
    end
  end

  // Stage 2 of the pipeline: Accumulation logic
  always @(posedge clk or negedge rstn) begin
    if (!rstn) begin
      accumulation_reg <= 'b0;
      valid_out_s1 <= 0;
      valid_i_s1 <= 0;
    end else if (valid_out_s0) begin
      accumulation_reg <= accumulation_reg << 1;
      accumulation_reg <= accumulation_reg | mult_result_reg;
      valid_out_s1 <= 1;
    end
  end

  // N-bit counter to track the number of accumulations
  always @(posedge clk or negedge rstn) begin
    if (!rstn) begin
      counter_reg <= 'b0;
    end else begin
      counter_reg <= counter_reg + 1;
    end
  end

  // Register valid output for 2-stage pipeline
  always @(posedge clk or negedge rstn) begin
    if (!rstn) begin
      valid_out_s2 <= 0;
    end else begin
      if (valid_out_s1) begin
        valid_out_s2 <= 1;
      end else begin
        valid_out_s2 <= valid_out_s1 & ~valid_out_s2;
      end
      if (counter_reg == N-1) begin
        valid_out <= valid_out_s2;
        counter_reg <= 'b0;
        accumulator_rst <= 1;
      end
    end
  end

  // ----------------------------------------
  // - Combinational Assignments
  // ----------------------------------------
  assign counter = count_rst ? 'b1 : (valid_i & rstn ? (counter_reg + 'd1) : counter_reg);  // Increment counter on valid input
  assign valid_out_s0 = (counter_reg == N-1);    // Assert valid_out_s0 when N accumulations are done
  assign count_rst = valid_out_s1;                  // Reset counter after N accumulations
  assign accumulator_rst = valid_out_s1;            // Reset accumulator after N accumulations
  assign result = accumulation_reg;              // Output final result assignment
  assign valid_out = valid_out_s1 & ~valid_out_s2; // Valid_out signal generation by detecting posedge of previous stages of valid out

endmodule : pipeline_mac

output.rtl/pkt_detector.sv:
module pkt_detector #(
    parameter PKT_CNT_WIDTH = 4
) (
    input  logic                       reset,
    input  logic                       clk,
    input  logic [7:0]                 data_in,
    input  logic                       data_k_flag,
    output logic [PKT_CNT_WIDTH - 1:0] pkt_count,
    output logic [159:0]               pkt_data,
    output logic                       mem_read_detected,
    output logic                       mem_write_detected,
    output logic                       io_read_detected,
    output logic                       io_write_detected,
    output logic                       cfg_read0_detected,
    output logic                       cfg_write0_detected,
    output logic                       cfg_read1_detected,
    output logic                       cfg_write1_detected,
    output logic                       completion_detected,
    output logic                       completion_data_detected,
    output logic                       error_detected
);

localparam [7:0] START_SYMBOL = 8'hFB, END_SYMBOL   = 8'hFD;
localparam       PKT_BYTES    = 20;

typedef enum logic [1:0] {
    S_IDLE     = 2'b00,
    S_ACTIVE   = 2'b01,
    S_WAIT_END = 2'b10,
    S_ERROR    = 2'b11
} state_t;

state_t curr_state, nxt_state;

logic [7:0]    byte_cnt;
logic [159:0]  pkt_reg;

// State Register
always_ff @(posedge clk or negedge reset) begin
    if (!reset)
        curr_state <= S_IDLE;
    else
        curr_state <= nxt_state;
end

// Next State Logic
always_comb begin
    case (curr_state)
        S_IDLE: 
            if ((data_in == START_SYMBOL) && (data_k_flag == 1'b1))
                nxt_state = S_ACTIVE;
            else
                nxt_state = S_IDLE;

        S_ACTIVE: 
            if (byte_cnt < PKT_BYTES)
                pkt_reg <= {pkt_reg[155:150], data_in};
            else
                nxt_state = S_WAIT_END;

        S_WAIT_END: 
            if (pkt_reg[159:152] == END_SYMBOL) begin
                pkt_count <= pkt_count + 1;
                pkt_data <= pkt_reg;
                completion_detected <= 1'b1;
                completion_data_detected <= 1'b1;
            end
            else begin
                nxt_state = S_ERROR;
                error_detected <= 1'b1;
            end

        S_ERROR: 
            if ((data_in == START_SYMBOL) && (data_k_flag == 1'b1))
                nxt_state = S_ACTIVE;
            else
                nxt_state = S_ERROR;

        default: nxt_state = S_IDLE;
    endcase
end

// Detect packet operation types
assign mem_read_detected = ~(pkt_reg[159:152] == 8'h00);
assign mem_write_detected = ~(pkt_reg[159:152] == 8'h01);
assign io_read_detected = ~(pkt_reg[159:152] == 8'h10);
assign io_write_detected = ~(pkt_reg[159:152] == 8'h11);
assign cfg_read0_detected = pkt_reg[158] == 8'h00;
assign cfg_write0_detected = pkt_reg[158] == 8'h01;
assign cfg_read1_detected = pkt_reg[157] == 8'h00;
assign cfg_write1_detected = pkt_reg[157] == 8'h01;

endmodule

output.rtl/cvdp_prbs_gen.sv:
module cvdp_prbs_gen #(
    parameter int POLY_LENGTH = 31,
    parameter int POLY_TAP = 3,
    parameter int WIDTH = 16
) (
    input logic clk,
    input logic rst,
    input logic [WIDTH-1:0] data_in,
    output logic [WIDTH-1:0] data_out
);

    // Internal signals
    logic [POLY_LENGTH-1:0] prbs_register [WIDTH-1:0];
    logic [POLY_LENGTH-1:0] feedback_bit;

    // Internal state
    logic [WIDTH-1:0] expected_prbs;

    // Parameter constraints
    always @* begin
        if (POLY_TAP > POLY_LENGTH) begin
            $error("POLY_TAP must be less than or equal to POLY_LENGTH");
        end
        if (POLY_TAP < 0) begin
            $error("POLY_TAP must be a positive integer");
        end
        if (WIDTH < 1) begin
            $error("WIDTH must be a positive integer");
        end
    end

    // Generator Mode
    always_ff @(posedge clk) begin
        if (rst) begin
            prbs_register <= {WIDTH{1'b1}};
            feedback_bit <= 0;
        end else if (CHECK_MODE == 0) begin
            feedback_bit = prbs_register[POLY_TAP] ^ prbs_register[POLY_LENGTH];
            prbs_register <= {feedback_bit{WIDTH-1}} << 1;
            expected_prbs <= prbs_register;
        end
    end

    // Checker Mode
    always_ff @(posedge clk) begin
        if (rst) begin
            data_out <= 0;
        end else if (CHECK_MODE == 1) begin
            feedback_bit = prbs_register[POLY_TAP] ^ prbs_register[POLY_LENGTH];
            prbs_register <= {feedback_bit{WIDTH-1}} << 1;
            expected_prbs <= prbs_register;
            data_out = data_in ^ expected_prbs;
        end
    end

endmodule

