module rounding #(
  parameter WIDTH = 24
)(
  input logic  [WIDTH-1:0] in_data      , // Input value for rounding
  input logic              sign    , // Indicates sign of input (1: negative, 0: positive)
  input logic              roundin , // Round bit
  input logic              stickyin, // Sticky bit for precision
  input logic  [2:0]       rm      , // Rounding mode
  output logic [WIDTH-1:0] out_data     , // Rounded output
  output logic             inexact , // Indicates precision loss
  output logic             cout    , // Carry-out_data signal
  output logic             r_up      // Indicates rounding up
);


  localparam RNE = 3'b000; 
  localparam RTZ = 3'b001; 
  localparam RUP = 3'b010; 
  localparam RDN = 3'b011; 
  localparam RMM = 3'b100; 

  logic rounding_up;

  always_comb begin
    case (rm)
      RNE: begin
        rounding_up = |(in_data[WIDTH-1:0] & sign) == 0;
        inexact = roundin | stickyin;
        out_data = in_data + (rounding_up ? 1 : 0);
        if (rounding_up) out_data[WIDTH-1] = 1;
        if (out_data[WIDTH-1] > in_data[WIDTH-1]) cout = 1;
        r_up = rounding_up;
      end
      RTZ: begin
        inexact = roundin | stickyin;
        out_data = in_data;
        if (out_data[WIDTH-1] > in_data[WIDTH-1]) cout = 1;
        r_up = 0;
      end
      RUP: begin
        rounding_up = |(in_data[WIDTH-1:0] & sign) == 1;
        inexact = roundin | stickyin;
        out_data = in_data + (rounding_up ? 1 : 0);
        r_up = rounding_up;
      end
      RDN: begin
        rounding_up = |(in_data[WIDTH-1:0] & sign) == -1;
        inexact = roundin | stickyin;
        out_data = in_data - (rounding_up ? 1 : 0);
        r_up = rounding_up;
      end
      RMM: begin
        rounding_up = |(in_data[WIDTH-1:0] & ~sign) == 0;
        inexact = roundin | stickyin;
        out_data = in_data + (rounding_up ? 1 : 0);
        r_up = rounding_up;
      end
      default: begin
        out_data = in_data;
        inexact = 0;
        cout = 0;
        r_up = 0;
      end
    endcase

  end

endmodule

output.rtl/copilot_rs_232.sv:
// Transmitter State Machine
reg [3:0] State, NextState;
wire MuxBit;

// State Transition Logic
always @ (posedge clock or negedge reset_neg) begin
    if (reset_neg == LOW) begin
        State <= 4'b0000; // Idle State
    end else if (tx_datain_ready) begin
        State <= State + 4'b0001; // Start State
    end else if (tx_transmitter_valid) begin
        NextState = State;
        if (State == 4'b0001) begin
            MuxBit = baud_pulse; // Data Bit 0
        end else if (State == 4'b0010) begin
            MuxBit = baud_pulse; // Data Bit 1
        end else if (State == 4'b0011) begin
            MuxBit = baud_pulse; // Data Bit 2
        end else if (State == 4'b0100) begin
            MuxBit = baud_pulse; // Data Bit 3
        end else if (State == 4'b0101) begin
            MuxBit = baud_pulse; // Data Bit 4
        end else if (State == 4'b0110) begin
            MuxBit = baud_pulse; // Data Bit 5
        end else if (State == 4'b0111) begin
            MuxBit = baud_pulse; // Data Bit 6
        end else if (State == 4'b1000) begin
            MuxBit = baud_pulse; // Data Bit 7
        end else if (State == 4'b1001) begin
            MuxBit = baud_pulse; // Stop Bit
        end
    end
end

// Output Multiplexer
always @ (posedge clock) begin
    case (State)
        4'b0000: tx_transmitter <= LOW;
        4'b0001: tx_transmitter <= baud_pulse;
        4'b0010: tx_transmitter <= baud_pulse;
        4'b0011: tx_transmitter <= baud_pulse;
        4'b0100: tx_transmitter <= baud_pulse;
        4'b0101: tx_transmitter <= baud_pulse;
        4'b0110: tx_transmitter <= baud_pulse;
        4'b0111: tx_transmitter <= baud_pulse;
        4'b1000: tx_transmitter <= baud_pulse;
        4'b1001: tx_transmitter <= HIGH;
        default: tx_transmitter <= LOW;
    endcase
end

