module sdram_controller (
    input clk,
    input reset,
    input [23:0] addr,
    input [15:0] data_in,
    output reg [15:0] data_out,
    output reg sdram_clk,
    output reg sdram_cke,
    output reg sdram_cs,
    output reg sdram_ras,
    output reg sdram_cas,
    output reg sdram_we,
    output reg sdram_addr,
    output reg sdram_ba,
    output reg [15:0] dq_out
);

    // State declaration
    typedef enum {INIT, IDLE, ACTIVATE, READ, WRITE, REFRESH} state_t;
    state_t state = INIT;

    // Timing constants
    localparam INIT_DURATION = 10;
    localparam IDLE_TIMEOUT = 1024;

    // FSM variables
    reg [1:0] fsm_reg;
    reg [IDLE_TIMEOUT - 1:0] fsm_counter;

    // FSM logic
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            fsm_reg <= INIT;
            fsm_counter <= 0;
        end else begin
            if (fsm_counter >= IDLE_TIMEOUT) begin
                fsm_counter <= 0;
                sdram_cs <= 1; // Activate SDRAM
                sdram_ras <= 1;
                sdram_cas <= 1;
                sdram_we <= 0;
                state <= REFRESH;
            end else if (state == IDLE) begin
                if (data_in != 0) begin
                    state <= ACTIVATE;
                    fsm_counter <= INIT_DURATION;
                end
            end else if (state == ACTIVATE) begin
                if (state_t_eq(state, READ) || state_t_eq(state, WRITE)) begin
                    state <= state_t_next(state);
                    fsm_counter <= 0;
                end else begin
                    fsm_counter <= fsm_counter + 1;
                end
            end
        end
    end

    // State transition logic
    function state_t state_t_next(state_t current_state);
        case (current_state)
            INIT: state_t_next = READ;
            READ: state_t_next = WRITE;
            WRITE: state_t_next = READ;
            REFRESH: state_t_next = IDLE;
            IDLE: state_t_next = READ; // Default to READ on IDLE
        endcase
    endfunction

    // Output logic
    always @(state, addr) begin
        case (state)
            INIT:
                sdram_clk <= 1;
                sdram_cke <= 1;
                sdram_cs <= 1;
                sdram_ras <= 0;
                sdram_cas <= 0;
                sdram_we <= 0;
                sdram_addr <= 0;
                sdram_ba <= 0;
                dq_out <= 0;
            READ:
                sdram_clk <= 1;
                sdram_cke <= 1;
                sdram_cs <= 1;
                sdram_ras <= 0;
                sdram_cas <= addr[15:0];
                sdram_we <= 0;
                sdram_addr <= addr[23:16];
                sdram_ba <= 0;
                dq_out <= data_in;
            WRITE:
                sdram_clk <= 1;
                sdram_cke <= 1;
                sdram_cs <= 1;
                sdram_ras <= 0;
                sdram_cas <= addr[15:0];
                sdram_we <= 1;
                sdram_addr <= addr[23:16];
                sdram_ba <= 0;
                dq_out <= data_in;
            REFRESH:
                sdram_clk <= 1;
                sdram_cke <= 1;
                sdram_cs <= 1;
                sdram_ras <= 0;
                sdram_cas <= 0;
                sdram_we <= 0;
                sdram_addr <= 0;
                sdram_ba <= 0;
                dq_out <= 0;
            IDLE:
                sdram_clk <= 1;
                sdram_cke <= 1;
                sdram_cs <= 1;
                sdram_ras <= 0;
                sdram_cas <= 0;
                sdram_we <= 0;
                sdram_addr <= 0;
                sdram_ba <= 0;
                dq_out <= 0;
        endcase
    end

endmodule

output.rtl/alu_seq.v:
module alu_seq (
    input i_clk,          // Clock signal
    input i_rst_b,        // Active-low asynchronous reset
    input [3:0] i_operand_a, // 4-bit input operand A
    input [3:0] i_operand_b, // 4-bit input operand B
    input [2:0] i_opcode,    // 3-bit operation code
    input [7:0] i_key_in,    // 8-bit security key input
    output reg [7:0] o_result // 8-bit operation result
);

    // Internal security key
    reg [7:0] p_key = 8'hAA;

    // State variable for the operation
    reg [7:0] temp_result;

    // Always block for clocked operations
    always @(posedge i_clk) begin
        if (i_rst_b) begin
            o_result <= 8'b0;
            temp_result <= 8'b0;
        end else begin
            if (i_key_in == p_key) begin
                case (i_opcode)
                    3'b000: temp_result <= i_operand_a + i_operand_b;
                    3'b001: temp_result <= i_operand_a - i_operand_b;
                    3'b010: temp_result <= i_operand_a * i_operand_b;
                    3'b011: temp_result <= i_operand_a & i_operand_b;
                    3'b100: temp_result <= i_operand_a | i_operand_b;
                    3'b101: temp_result <= ~i_operand_a;
                    3'b110: temp_result <= i_operand_a ^ i_operand_b;
                    3'b111: temp_result <= ~(i_operand_a ^ i_operand_b);
                    default: temp_result <= 8'b0;
                endcase
                o_result <= temp_result;
            end else begin
                o_result <= 8'b0;
            end
        end
    end

endmodule

output.rtl/secure_read_write_bus_interface.v:
module secure_read_write_bus_interface #(
    parameter p_data_width = 8,
    parameter p_addr_width = 8,
    parameter p_configurable_key = 8'hAA
) (
    input wire [p_addr_width-1:0] i_addr,
    input wire i_capture_pulse,
    input wire i_read_write_enable,
    input wire i_key_in,
    input wire i_reset_bar,
    output reg [p_data_width-1:0] o_data_out,
    output reg o_error
);

    // Internal registers
    reg [p_data_width-1:0] internal_data;
    reg [7:0] internal_key;

    // Reset condition
    always @(posedge i_capture_pulse or posedge i_reset_bar) begin
        if (i_reset_bar == 1'b0) begin
            internal_data <= 0;
            internal_key <= p_configurable_key;
            o_data_out <= 0;
            o_error <= 1'b0;
        end
    end

    // Comparison of input key with internal key
    always @(posedge i_capture_pulse) begin
        if (i_read_write_enable) begin
            if (internal_key == i_key_in) begin
                o_data_out <= internal_data;
                o_error <= 1'b0;
            end else begin
                o_data_out <= 0;
                o_error <= 1'b1;
            end
        end
    end

    // Write operation
    always @(posedge i_capture_pulse) begin
        if (!i_read_write_enable) begin
            if (internal_key == i_key_in) begin
                internal_data <= i_data_in;
            end else begin
                o_error <= 1'b1;
                o_data_out <= 0;
            end
        end
    end

    // Read operation
    always @(posedge i_capture_pulse) begin
        if (i_read_write_enable) begin
            if (internal_key == i_key_in) begin
                o_data_out <= internal_data;
                o_error <= 1'b0;
            end else begin
                o_data_out <= 0;
                o_error <= 1'b1;
            end
        end
    end

endmodule

output.rtl/secure_variable_timer.v:
module secure_variable_timer (
    input wire i_clk,           // Clock signal (rising-edge triggered)
    input wire i_rst_n,         // Active-low synchronous reset signal
    input wire i_data_in,       // Serial data input
    output reg [3:0] o_time_left, // 4-bit output showing remaining time during counting phase
    output reg o_processing,    // Asserted high when the timer is actively counting
    output reg o_completed,     // Asserted high when the timer completes its delay
    input wire i_ack            // Acknowledgment signal to reset after completion
);

    // Internal registers
    reg [3:0] delay;            // Holds the 4-bit delay value
    reg [3:0] counter;          // Counter for counting cycles
    reg [3:0] current_delay;    // Current delay value being counted

    // State machine (FSM) definitions
    localparam IDLE = 0;
    localparam CONFIGURE = 1;
    localparam COUNT = 2;
    localparam DONE = 3;

    // State register
    reg [2:0] state;

    // Input and output logic
    always @(posedge i_clk or negedge i_rst_n) begin
        if (!i_rst_n) begin
            state <= IDLE;
            counter <= 0;
            current_delay <= 0;
        end else begin
            case (state)
                IDLE: begin
                    if (i_data_in == 4'b1101) begin
                        state <= CONFIGURE;
                        counter <= 0;
                    end
                end
                CONFIGURE: begin
                    if (i_data_in[3:0] != 4'b0000) begin
                        delay <= i_data_in[3:0];
                        state <= COUNT;
                    end
                end
                COUNT: begin
                    counter <= counter + 1;
                    if (counter >= delay + 999) begin
                        o_processing <= 1;
                        o_time_left <= current_delay - (counter - (delay + 999));
                        state <= DONE;
                    end
                end
                DONE: begin
                    o_completed <= 1;
                    if (i_ack) begin
                        state <= IDLE;
                    end
                end
            endcase
        end
    end

    // Delay value logic
    always @(posedge i_clk) begin
        if (state == COUNT) begin
            current_delay <= current_delay - 1;
            if (current_delay == 0) begin
                state <= DONE;
                counter <= 0;
            end
        end
    end

endmodule

