module signal_correlator(
    input clk,
    input reset,
    input [7:0] input_signal,
    input [7:0] reference_signal,
    output reg [3:0] correlation_output // 4-bit output
);

integer i;
reg [3:0] sum;  

always @(posedge clk or posedge reset) begin
    if (reset) begin
        correlation_output <= 0;
        sum = 0;  
    end else begin
        sum = 0;  
        for (i = 0; i < 8; i = i + 1) begin
            sum = sum + (input_signal[i] & reference_signal[i]); 
        end
    end
end

endmodule

output.rtl/signedadder.v:
module signedadder #(parameter DATA_WIDTH = 8)(
    input i_clk,
    input i_rst_n,
    input i_start,
    input i_enable,
    input i_mode,
    input i_clear,
    input [DATA_WIDTH-1:0] i_operand_a,
    input [DATA_WIDTH-1:0] i_operand_b,
    output reg [DATA_WIDTH-1:0] o_resultant_sum,
    output reg o_overflow,
    output reg o_ready,
    output reg [1:0] o_status
);

    // Internal registers
    reg [DATA_WIDTH-1:0] a_reg, b_reg;
    reg [1:0] status;

    // State logic
    always @(posedge i_clk or posedge i_rst_n) begin
        if (i_rst_n) begin
            status <= 2'b00;
            o_resultant_sum <= {DATA_WIDTH{1'b0}};
            o_overflow <= 0;
            o_ready <= 0;
        end else begin
            case (status)
                2'b00: if (i_start) begin
                            status <= 2'b01;
                            a_reg <= i_operand_a;
                            b_reg <= i_operand_b;
                        end
                2'b01: begin
                            if (i_clear) begin
                                status <= 2'b00;
                                a_reg <= {DATA_WIDTH{1'b0}};
                                b_reg <= {DATA_WIDTH{1'b0}};
                            end
                            status <= 2'b10;
                        end
                2'b10: begin
                            if (i_mode == 0) begin
                                o_resultant_sum <= a_reg + b_reg;
                                o_overflow <= (a_reg[DATA_WIDTH-1] & b_reg[DATA_WIDTH-1] &
                                                (~a_reg[DATA_WIDTH-2] | ~b_reg[DATA_WIDTH-2]));
                            end else if (i_mode == 1) begin
                                o_resultant_sum <= a_reg - b_reg;
                                o_overflow <= (a_reg[DATA_WIDTH-1] & b_reg[DATA_WIDTH-1] &
                                                (~a_reg[DATA_WIDTH-2] | ~b_reg[DATA_WIDTH-2]));
                            end
                            o_ready <= 1;
                            status <= 2'b11;
                        end
                2'b11: begin
                            o_resultant_sum <= o_resultant_sum;
                            o_overflow <= o_overflow;
                            o_ready <= o_ready;
                            status <= 2'b00;
                        end
                    end
        end
    end

endmodule

output.rtl/unique_number_identifier.v:
module unique_number_identifier #(
    parameter p_bit_width = 8,
    parameter p_max_numbers = 16
) (
    input wire i_clk,
    input wire i_rst_n,
    input wire i_ready,
    input wire [p_bit_width-1:0] i_number,
    output reg [p_bit_width-1:0] o_unique_number
);

    // Internal state storage
    reg [p_bit_width-1:0] number_count [0:p_max_numbers-1];
    reg [p_bit_width-1:0] unique_number;

    // State machine
    always @(posedge i_clk or posedge i_rst_n) begin
        if (i_rst_n) begin
            // Reset internal states
            number_count <= {p_bit_width{1'b0}};
            unique_number <= 0;
        end else if (i_ready) begin
            // Count occurrences of each number
            number_count <= number_count + {i_number, number_count[i_number]};

            // Identify unique number
            for (int i=0; i<p_max_numbers; i++) begin
                if (number_count[i] == 1) begin
                    unique_number <= i_number;
                    break;
                end
            end
        end
    end

    // Output logic
    always @(i_ready or unique_number) begin
        if (i_ready) begin
            o_unique_number <= unique_number;
        end
    end

endmodule

output.rtl/pipelined_skid_buffer.sv:
module pipelined_skid_buffer(
    input wire clock,
    input wire rst,

    input wire [3:0] data_i,
    input wire valid_i,
    output wire ready_o,
    output wire valid_o,
    output wire [3:0] data_o,
    input wire ready_i

    );

    wire buffer_flag;
    wire buffer_reg;

    // Register for intermediate storage
    register reg1(
        .clk(clock),
        .rst(rst),
        .data_in(buffer_reg),
        .valid_in(valid_i),
        .ready_out(ready_o),
        .valid_out(valid_o),
        .data_out(data_o),
        .ready_in(ready_i)
    );

    // Skid buffer logic
    always @(posedge clock or posedge rst) begin
        if (rst) begin
            buffer_reg <= 4'b0;
            buffer_flag <= 0;
        end else begin
            if (ready_i && !valid_i) begin
                buffer_reg <= data_i;
                buffer_flag <= 1;
            end else if (buffer_flag && valid_i && !ready_i) begin
                buffer_reg <= data_i;
            end
        end
    end

    // Connect buffer_reg to data_o when ready
    assign data_o = buffer_reg;
    assign valid_o = buffer_flag;
    assign ready_o = buffer_flag & ready_i;

endmodule

module register(
    input clk,
    input rst,

    input [3:0]data_in,
    input valid_in,
    output ready_out,
    output valid_out,
    output [3:0]data_out,
    input ready_in    
    );

    reg [3:0]data_reg;
    reg valid_reg;

    // Register logic
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            data_reg <= 4'b0;
            valid_reg <= 0;
        end else if (valid_in && ready_in) begin
            data_reg <= data_in;
            valid_reg <= 1;
        end else if (valid_reg) begin
            data_reg <= data_reg;
        end
    end

    // Output connections
    assign data_out = data_reg;
    assign valid_out = valid_reg;
    assign ready_out = valid_reg & ready_in;

endmodule

module skid_buffer(

    input  clk,
    input  reset ,

    input  [3:0]i_data,
    input  i_valid,
    output o_ready,

    output [3:0]o_data,
    output o_valid,
    input  i_ready

    );

    wire buffer_flag;
    wire buffer_reg;

    // Skid buffer logic
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            buffer_reg <= 4'b0;
            buffer_flag <= 0;
        end else begin
            if (i_ready && !i_valid) begin
                buffer_reg <= i_data;
                buffer_flag <= 1;
            end else if (buffer_flag && i_valid && !i_ready) begin
                buffer_reg <= i_data;
            end
        end
    end

    // Output connections
    assign o_data = buffer_reg;
    assign o_valid = buffer_flag;
    assign o_ready = buffer_flag & i_ready;

endmodule

input.rtl/sobel_filter.sv:
module sobel_filter (
    input            clk,
    input            rst_n,
    input      [7:0] pixel_in,
    input            valid_in,
    output reg [7:0] edge_out,
    output reg       valid_out
);
    // Internal signals for gradients
    reg signed [10:0] Gx, Gy;  // To accommodate larger values after convolution
    reg [7:0] pixel_buffer[0:8]; // 3x3 pixel window
    integer i;

    // Parameters for thresholding
    parameter THRESHOLD = 11'd128;

    // Sliding window logic
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            for (i = 0; i < 9; i = i + 1) begin
                pixel_buffer[i] <= 8'd0;
            end    
        end else if (valid_in) begin
            pixel_buffer[8] <= pixel_buffer[7];
            pixel_buffer[7] <= pixel_buffer[6];
            pixel_buffer[6] <= pixel_buffer[5];
            pixel_buffer[5] <= pixel_buffer[4];
            pixel_buffer[4] <= pixel_buffer[3];
            pixel_buffer[3] <= pixel_buffer[2];
            pixel_buffer[2] <= pixel_buffer[1];
            pixel_buffer[1] <= pixel_buffer[0];
            pixel_buffer[0] <= pixel_in;
        end
    end

    // Sobel convolution and edge detection
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            Gx        <= 11'sd0;
            Gy        <= 11'sd0;
            edge_out  <= 8'd0;
            valid_out <= 1'b0;
        end else if (valid_in) begin
            // Compute Gx and Gy using Sobel kernels
            Gx <= -pixel_buffer[6] - (pixel_buffer[3] << 1) - pixel_buffer[0]
                  +pixel_buffer[8] + (pixel_buffer[5] << 1) + pixel_buffer[2];
            Gy <= -pixel_buffer[6] - (pixel_buffer[7] << 1) - pixel_buffer[8]
                  +pixel_buffer[0] + (pixel_buffer[1] << 1) + pixel_buffer[2];

            // Compute gradient magnitude (simplified as |Gx| + |Gy|)
            edge_out <= ((Gx < 0 ? -Gx : Gx) + (Gy < 0 ? -Gy : Gy)) > THRESHOLD ? 8'd255 : 8'd0;

            // Set valid output
            valid_out <= 1'b1;
        end else begin
            valid_out <= 1'b0;
        end
    end
endmodule

