module sorting_engine #(
    parameter N = 8,     
    parameter WIDTH = 8  
)(
    input  wire                clk,
    input  wire                rst,
    input  wire                start,
    input  wire [N*WIDTH-1:0]  in_data,
    output reg                 done,
    output reg [N*WIDTH-1:0]   out_data
);
    localparam IDLE = 2'd0,
               LOAD = 2'd1,
               SORT = 2'd2,
               DONE = 2'd3;

    reg [1:0]  state, next_state;
    reg [WIDTH-1:0] data_array [0:N-1];
    reg [$clog2(N/2+1)-1:0] pass_cnt;
    reg [$clog2(N/2+1)-1:0] pair_idx;

    wire [$clog2(N/2+1)-1:0] pairs_in_this_pass;
    assign pairs_in_this_pass = (pass_cnt[0] == 1'b0) ? (N/2) : ( (N/2) > 0 ? (N/2) - 1 : 0 );

    // Initialize data array and done signal
    always @ (posedge clk or posedge rst) begin
        if (rst) begin
            state <= IDLE;
            data_array <= {N{1'b0}};
            done <= 1'b0;
        end else if (start && state == IDLE) begin
            state <= LOAD;
            data_array <= in_data;
            done <= 1'b0;
        end
    end

    // State machine
    always @ (state) begin
        case (state)
            IDLE: begin
                if (start) begin
                    state <= LOAD;
                end else begin
                    state <= DONE;
                end
            end
            LOAD: begin
                if (data_array[pair_idx] > data_array[pair_idx + 1]) begin
                    state <= SORT;
                    pair_idx <= pair_idx + 1;
                end else begin
                    state <= DONE;
                end
            end
            SORT: begin
                pass_cnt <= pass_cnt + 1;
                if (pair_idx == (N/2) - 1) begin
                    state <= DONE;
                end else begin
                    pair_idx <= pair_idx + 1;
                    state <= SORT;
                end
            end
            DONE: begin
                out_data <= data_array;
                done <= 1'b1;
            end
        end
    end

    // Update state machine on clock edges
    always @ (posedge clk) begin
        next_state <= state;
        if (rst) next_state <= IDLE;
    end

endmodule

// Insert code here to implement the combinational logic for the FSM of the Counting sort algorithm.
always @(*) begin
    if (start && !rst) begin
        current_state <= S_LOAD_INPUT;
        load_cnt      <= N;
        next_state    <= S_FIND_MAX;
    end else begin
        current_state <= next_state;
    end
end

// State: S_LOAD_INPUT
always @(posedge clk) begin
    if (current_state == S_LOAD_INPUT) begin
        for (i = 0; i < N; i = i + 1) begin
            data_array[i] <= in_data[i*WIDTH +: WIDTH];
        end
        next_state <= S_FIND_MAX;
    end
end

// State: S_FIND_MAX
always @(posedge clk) begin
    if (current_state == S_FIND_MAX) begin
        max_val <= 0;
        find_cnt  <= 0;
        next_state <= S_COUNT;
        for (i = 0; i < N; i = i + 1) begin
            if (data_array[i] > max_val) begin
                max_val <= data_array[i];
                next_max_val <= max_val;
            end
        end
    end
end

// State: S_COUNT
always @(posedge clk) begin
    if (current_state == S_COUNT) begin
        count_cnt <= 0;
        next_state <= S_PREFIX_SUM;
        for (i = 0; i < (1<<WIDTH); i = i + 1) begin
            if (max_val == i) begin
                count_array[i] <= 0;
            end else begin
                count_array[i] <= count_array[i] + (data_array == max_val);
            end
        end
    end
end

// State: S_PREFIX_SUM
always @(posedge clk) begin
    if (current_state == S_PREFIX_SUM) begin
        prefix_cnt <= 0;
        next_state <= S_BUILD_OUTPUT;
        prefix_cnt <= count_array;
    end
end

// State: S_BUILD_OUTPUT
always @(posedge clk) begin
    if (current_state == S_BUILD_OUTPUT) begin
        build_cnt <= 0;
        next_state <= S_COPY_OUTPUT;
        for (i = N-1; i >= 0; i = i - 1) begin
            out_array[i] <= (count_array == prefix_cnt) ? (data_array +: WIDTH) : {WIDTH{1'b0}};
        end
    end
end

// State: S_COPY_OUTPUT
always @(posedge clk) begin
    if (current_state == S_COPY_OUTPUT) begin
        copy_cnt <= 0;
        next_state <= S_DONE;
        next_out_data <= out_array;
    end
end

// State: S_DONE
always @(posedge clk) begin
    if (current_state == S_DONE) begin
        done <= 1'b1;
        next_state <= S_IDLE;
    end
end

// State: S_IDLE
always @(posedge clk) begin
    if (current_state == S_IDLE) begin
        if (start && !rst) begin
            current_state <= S_LOAD_INPUT;
            load_cnt      <= N;
        end else begin
            current_state <= S_IDLE;
        end
    end
end

