module static_branch_predict (

  // Instruction from fetch stage
  input  logic [31:0] fetch_rdata_i,
  input  logic [31:0] fetch_pc_i,
  input  logic [31:0] register_addr_i,
  input  logic        fetch_valid_i,

  // Prediction for supplied instruction
  output logic        predict_branch_taken_o,
  output logic [31:0] predict_branch_pc_o
);
  logic [31:0] reg_addr;
  logic [31:0] imm_jal_type;
  logic [31:0] imm_jalr_type;
  logic [31:0] imm_b_type;
  logic [31:0] imm_cj_type;
  logic [31:0] imm_cb_type;

  logic [31:0] branch_imm;

  logic [31:0] instr;

  logic instr_jal;
  logic instr_jalr;
  logic instr_b;
  logic instr_cj;
  logic instr_cb;

  logic instr_b_taken;


  localparam OPCODE_BRANCH = 7'h63;
  localparam OPCODE_JAL    = 7'h6F;
  localparam OPCODE_JALR   = 7'h67;

  assign instr = fetch_rdata_i;
  assign reg_addr = register_addr_i;

  assign imm_jal_type = {{12{instr[31]}}, instr[19:12], instr[20], instr[30:21], 1'b0 };
  assign imm_jalr_type = {{20{instr[31]}}, instr[31:20]}+reg_addr;
  assign imm_b_type = { {19{instr[31]}}, instr[31], instr[7], instr[30:25], instr[11:8], 1'b0 };

  assign imm_cj_type = { {20{instr[12]}}, instr[12], instr[8], instr[10:9], instr[6], instr[7],
    instr[2], instr[11], instr[5:3], 1'b0 };

  assign imm_cb_type = { {23{instr[12]}}, instr[12], instr[6:5], instr[2], instr[11:10],
    instr[4:3], 1'b0};

  assign instr_b    = instr[6:0] == OPCODE_BRANCH;
  assign instr_jal  = instr[6:0] == OPCODE_JAL;
  assign instr_jalr = instr[6:0] == OPCODE_JALR;

  assign instr_cb = (instr[1:0] == 2'b01) & ((instr[15:13] == 3'b110) | (instr[15:13] == 3'b111));
  assign instr_cj = (instr[1:0] == 2'b01) & ((instr[15:13] == 3'b101) | (instr[15:13] == 3'b001));

  always_comb begin
    branch_imm = imm_b_type;

    case(1'b1)
      instr_jal  : branch_imm = imm_jal_type;
      instr_jalr : branch_imm = imm_jalr_type;
      instr_b    : branch_imm = imm_b_type;
      instr_cj   : branch_imm = imm_cj_type;
      instr_cb   : branch_imm = imm_cb_type;
      default    : ;
    endcase
  end
  assign predict_branch_pc_o    = fetch_pc_i + branch_imm; 
  assign instr_b_taken = (instr_b & imm_b_type[31]) | (instr_cb & imm_cb_type[31]);
  assign predict_branch_taken_o = fetch_valid_i & (instr_jal | instr_jalr | instr_cj | instr_b_taken);

endmodule

always @(*) begin
  instr = fetch_rdata_i;
  reg_addr = register_addr_i;

  // Instruction decoding
  instr_jal = (instr[6:0] == 7'h6F);
  instr_jalr = (instr[6:0] == 7'h67);
  instr_b = (instr[6:0] == 7'h63);
  instr_cj = (instr[6:0] == 7'h40); // Assuming CJ starts with 7'h40
  instr_cb = (instr[6:0] == 7'h41); // Assuming CB starts with 7'h41

  // Branch Immediate Selection
  if (instr_jal) begin
    imm_jal_type = {reg_addr, {instr[15:0], '0}};
  end
  else if (instr_jalr) begin
    imm_jalr_type = instr[11:0] + reg_addr;
  }
  else if (instr_b) begin
    imm_b_type = {instr[30:2], instr[2:0], '0}; // Sign extension
  end
  else if (instr_cj) begin
    imm_cj_type = instr[15:8]; // Extracting compressed immediate
  end
  else if (instr_cb) begin
    imm_cb_type = instr[15:8]; // Extracting compressed immediate
  end
  else begin
    branch_imm = imm_b_type;
  }

  // Branch Taken Decision
  instr_b_taken = (imm_b_type[31] == 1); // Assuming B-type branch is sign-extended

  // Branch Prediction
  predict_branch_taken_o = (instr_jal || instr_jalr || instr_b || instr_cj) || instr_b_taken;

  // Branch Target Address Calculation
  predict_branch_pc_o = fetch_pc_i + branch_imm;
end

// Offset Calculation for different branch types
assign imm_jal_type = { {12{instr[31]}}, instr[19:12], instr[20], instr[30:21], 1'b0 };
assign imm_jalr_type = {{20{instr[31]}}, instr[31:20]} + register_addr;
assign imm_b_type =  { {19{instr[31]}}, instr[31], instr[7], instr[30:25], instr[11:8], 1'b0 };
assign imm_cj_type = { {20{instr[12]}}, instr[12], instr[8], instr[10:9], instr[6], instr[7], instr[2], instr[11], instr[5:3], 1'b0 };
assign imm_cb_type = { {23{instr[12]}}, instr[12], instr[6:5], instr[2], instr[11:10], instr[4:3], 1'b0 };

// Branch Prediction Logic
assign predict_branch_taken_o = (predict_confidence_o > 50);
assign predict_branch_pc_o = (predict_branch_taken_o ? fetch_pc_i + predict_branch_offset_o : 0);

// Confidence Level Calculation
assign predict_confidence_o = (fetch_valid_i) ? (instr_b_taken ? 90 : 50) : 0;

// Exception Detection
assign predict_exception_o = (fetch_pc_i % 4 != 0) ? 1'b1 : 1'b0;

// Branch Type Identification
assign instr_jal = (instr[6:0] == 7'h6F);
assign instr_jalr = (instr[6:0] == 7'h67) && (fetch_valid_i);
assign instr_b = (instr[6:0] == 7'h63) && (fetch_valid_i);
assign instr_cj = (instr[6:0] == 7'h66) && (fetch_valid_i);
assign instr_cb = (instr[6:0] == 7'h65) && (fetch_valid_i);

// Branch Prediction Decision
assign instr_b_taken = instr_b && (instr[31] == 1);

// Branch Target Address
assign predict_branch_offset_o = (instr_jal) ? imm_jal_type :
                                 (instr_jalr) ? imm_jalr_type :
                                 (instr_b) ? imm_b_type :
                                 (instr_cj) ? imm_cj_type :
                                 (instr_cb) ? imm_cb_type : 0;

// Type of Branch Instruction
assign predict_branch_type_o = (instr_jal) ? 2'b00 :
                               (instr_jalr) ? 2'b01 :
                               (instr_b) ? 2'b10 :
                               (instr_cj) ? 2'b11 : 2'b00;

endmodule

