module sync_serial_communication_top (
    input clk,
    input reset_n,
    input [63:0] data_in,
    input [2:0] sel,
    output reg serial_out,
    output reg done,
    output reg serial_clk
);

    wire [5:0] data_width;

    // Instantiate transmitter block
    tx_block tx_inst (.clk(clk), .reset_n(reset_n), .data_in(data_in), .sel(sel),
                     .serial_out(serial_out), .done(done), .serial_clk(serial_clk),
                     .data_width(data_width));

    // Instantiate receiver block
    rx_block rx_inst (.clk(clk), .reset_n(reset_n), .data_in(serial_out), .sel(sel),
                      .serial_clk(serial_clk), .data_out(data_out), .done(done));

    // Connect data_out to the output
    assign data_out = rx_inst.data_out;

endmodule

`timescale 1ns / 1ps
module sync_serial_communication_tx_rx(
    input clk,                     // Clock signal
    input reset_n,                 // Active low reset signal
    input [2:0] sel,               // Selection signal for TX block
    input [63:0] data_in,          // 64-bit data input for TX block
    output reg [63:0] data_out,    // 64-bit data output from RX block
    output reg done                // Done signal indicating completion
);

// Internal signals
wire tx_reg, rx_reg;                 // Register for internal data transfer
wire tx_done, rx_done;                // Done signals for TX and RX blocks
wire serial_clk_in;                  // Serial clock generated by TX block

// Instantiate the TX and RX blocks
tx_block uut_tx_block (
    .clk(clk),                       // Clock input to TX block
    .reset_n(reset_n),               // Reset input to TX block
    .data_in(data_in),               // 64-bit data input to TX block
    .sel(sel),                       // Selection signal to TX block
    .data_out(tx_reg),               // 64-bit data output from TX block
    .done(tx_done),                  // Done signal from TX block
    .serial_clk(serial_clk_in)       // Serial clock output from TX block
);

rx_block uut_rx_block (
    .clk(clk),                       // Clock input to RX block
    .reset_n(reset_n),               // Reset input to RX block
    .data_in(rx_reg),                // 64-bit data input to RX block
    .sel(sel),                       // Selection signal to RX block
    .data_out(data_out),            // 64-bit data output from RX block
    .done(rx_done)                  // Done signal from RX block
);

// Combined always block for TX and RX
always @(posedge clk or negedge reset_n) begin
    if (!reset_n) begin
        tx_reg <= 64'h0;
        rx_reg <= 64'h0;
        bit_count <= 7'h0;
        reg_count <= 7'h0;
        temp_reg_count <= 7'h0;
        done <= 1'b0;
    end
    else begin
        case(sel)
            3'b000: begin
                tx_reg <= 64'h0;
                rx_reg <= 64'h0;
                bit_count <= 7'd0;
                reg_count <= 7'd0;
            end
            3'b001: begin
                tx_reg <= {56'h0, data_in[7:0]};
                rx_reg <= {56'h0, data_in[7:0]};
                bit_count <= 7'd7;
                reg_count <= 7'd7;
            end
            3'b010: begin
                tx_reg <= {48'h0, data_in[15:0]};
                rx_reg <= {48'h0, data_in[15:0]};
                bit_count <= 7'd15;
                reg_count <= 7'd15;
            end
            3'b011: begin
                tx_reg <= {32'h0, data_in[31:0]};
                rx_reg <= {32'h0, data_in[31:0]};
                bit_count <= 7'd31;
                reg_count <= 7'd31;
            end
            3'b100: begin
                tx_reg <= data_in;
                rx_reg <= data_in;
                bit_count <= 7'd63;
                reg_count <= 7'd63;
            end
            default: begin
                tx_reg <= 64'h0;
                rx_reg <= 64'h0;
                bit_count <= 7'h0;
                reg_count <= 7'h0;
            end
        end
    end

    // Calculate serial clock with added 3-cycle latency
    case(reg_count)
        7'd0: serial_clk_in = 1'b0;
        7'd1: serial_clk_in = clk && temp_reg_count !== 7'd0;
        7'd2: serial_clk_in = clk && temp_reg_count !== 7'd1;
        7'd3: serial_clk_in = clk;
        default: begin
            serial_clk_in = clk && temp_reg_count !== 7'd2;
        end
    end

    // Calculate done signals with added 3-cycle latency
    case(bit_count)
        7'd0: done = 1'b0;
        7'd1: done = 1'b0;
        7'd2: done = 1'b0;
        7'd3: done = 1'b0;
        7'd4: done = 1'b0;
        7'd5: done = 1'b0;
        7'd6: done = 1'b0;
        7'd7: done = 1'b0;
        7'd8: done = 1'b1;
        default: begin
            done = 1'b0;
        end
    end
end

endmodule

///// tx_block
module tx_block(
    input clk,               // Clock input
    input reset_n,           // Active-low reset input
    input [63:0] data_in,    // 64-bit parallel data input
    input [2:0] sel,         // Selection input to choose data width
    output reg serial_out,   // Serial data output
    output reg done,         // Done signal indicating completion of transmission
    output reg serial_clk        // Clock for serial data transmission
);

// Internal registers
reg [63:0] data_reg;         // Register to hold the data being transmitted
reg [6:0] bit_count;         // Counter to track number of bits to transmit
reg [6:0] reg_count;         // Register for counting bits for serial clock control
reg [6:0] temp_reg_count;    // Temporary register to track reg_count

// Sequential block for state control and data selection
always @(posedge clk or negedge reset_n) begin
    if (!reset_n) begin
        data_reg     <= 64'h0;
        bit_count    <= 7'd0;
        reg_count    <= 7'h0;
        temp_reg_count <= 7'h0;
    end else begin
        bit_count <= bit_count + 1'b1;
        reg_count <= reg_count + 1'b1;
        temp_reg_count <= temp_reg_count + 1'b1;
    end
end

// Generate serial clock based on reg_count
always @(posedge clk or negedge reset_n) begin
    if (!reset_n) begin
        temp_reg_count <= 7'h0;
    end
    else begin
        temp_reg_count <= reg_count;
    end
end

// Sequential logic to drive the serial_out signal based on reg_count and bit_count
always @(posedge clk or negedge reset_n) begin
    if (!reset_n) begin
        serial_out <= 1'b0;
    end
    else if(reg_count > 7'h0 || bit_count > 7'h0) begin
        serial_out <= data_reg[bit_count - 1];
    end
end

// Set the done signal when transmission is complete (bit_count reaches zero)
always @(posedge clk or negedge reset_n) begin
    if (!reset_n) begin
        done <= 1'b0;
    end 
    else begin
        if(bit_count == 7'h0) begin
            done <= 1'b1;
        end
        else begin
            done <= 1'b0;
        end
    end
end

endmodule

///// rx_block
module rx_block(
    input wire clk,  			    // clock input
    input wire reset_n,			    // Active-low reset
    input wire data_in,			    // Serial input data
    input wire serial_clk,		    // Clock signal for serial data
    input wire [2:0] sel,           // Selection output to choose data width
    output reg [63:0] data_out  	// Parallel output data after serial operation
)

// Internal registers
reg [63:0] data_reg;		    // Register to hold incoming serial data
reg [7:0] bit_count;		    // Counter for the number of bits received
reg [7:0] count;			    // General purpose counter to sync with bit_count

// Sequential logic block to capture serial data on the rising edge of serial_clk
always @(posedge serial_clk or negedge reset_n) begin
    if (!reset_n) begin
        data_reg <= 64'h0;
        bit_count <= 8'd0;
    end
    else if(done == 1'b1) begin
        data_reg <= 64'h0;
        bit_count <= 8'b0;
    end
    else begin
        bit_count <= bit_count;
        data_reg[bit_count] <= data_in;
    end
end

// Sequential logic block to monitor the completion of data reception and update outputs
always @(posedge clk or negedge reset_n) begin
    if (!reset_n) begin
        count <= 8'd0;
        done <= 1'b0;
        data_out <= 64'h0;
    end
    else if(count >= bit_count && count != 8'd0) begin
        done <= 1'b1;
        case(sel)
            3'b000: data_out <= 64'h0;
            3'b001: data_out <= data_reg;
            3'b010: data_out <= data_reg;
            3'b011: data_out <= data_reg;
            3'b100: data_out <= data_reg;
            default: data_out <= 64'h0;
        end
    end
    else if(bit_count > 8'd0) begin
        count <= count + 1'b1;
        done <= 1'b0;
    end
    else begin
        count <= 8'd0;
        done <= 1'b0;
    end
end

endmodule

output.rtl/thermostat.v:
module thermostat(
    input [5:0] i_temp_feedback,
    input i_fan_on,
    input i_enable,
    input i_fault,
    input i_clr,
    input i_clk,
    input i_rst,
    output reg o_heater_full,
    output reg o_heater_medium,
    output reg o_heater_low,
    output reg o_aircon_full,
    output reg o_aircon_medium,
    output reg o_aircon_low,
    output reg o_fan,
    output reg [2:0] o_state
);

    // FSM state register
    reg [2:0] fsm_state = 3'b000; // Default state: AMBIENT

    // Asynchronous reset
    always @(posedge i_clk or posedge i_rst) begin
        if (i_rst)
            fsm_state <= 3'b000;
    end

    // Fault state logic
    always @(i_fault or i_clr or i_enable) begin
        if (i_fault)
            fsm_state <= 3'b000;
        else if (i_clr)
            fsm_state <= 3'b000;
        else if (i_enable == 0)
            fsm_state <= 3'b000;
    end

    // FSM state transition logic
    always @(posedge i_clk) begin
        case (fsm_state)
            3'b000: // AMBIENT
                if (i_temp_feedback[5])
                    fsm_state = 3'b100; // COOL_LOW
                else if (i_temp_feedback[4])
                    fsm_state = 3'b101; // COOL_MED
                else if (i_temp_feedback[3])
                    fsm_state = 3'b110; // COOL_FULL
                else
                    fsm_state = 3'b000;

            3'b100: // COOL_LOW
                if (i_temp_feedback[2])
                    fsm_state = 3'b010; // HEAT_LOW
                else if (i_temp_feedback[1])
                    fsm_state = 3'b011; // HEAT_MED
                else if (i_temp_feedback[0])
                    fsm_state = 3'b000; // AMBIENT

            3'b101: // COOL_MED
                if (i_temp_feedback[5])
                    fsm_state = 3'b010; // HEAT_LOW
                else if (i_temp_feedback[4])
                    fsm_state = 3'b011; // HEAT_MED
                else if (i_temp_feedback[3])
                    fsm_state = 3'b110; // COOL_FULL
                else
                    fsm_state = 3'b000;

            3'b110: // COOL_FULL
                if (i_temp_feedback[5])
                    fsm_state = 3'b000; // AMBIENT
                else if (i_temp_feedback[4])
                    fsm_state = 3'b010; // HEAT_LOW
                else if (i_temp_feedback[3])
                    fsm_state = 3'b011; // HEAT_MED
                else
                    fsm_state = 3'b100; // COOL_LOW

            3'b000: // AMBIENT
                // No transitions needed, FSM remains in AMBIENT
        endcase
    end

    // Output logic
    always @(*) begin
        case (fsm_state)
            3'b000:
                o_heater_full = 0;
                o_heater_medium = 0;
                o_heater_low = 0;
                o_aircon_full = 0;
                o_aircon_medium = 0;
                o_aircon_low = 0;
                o_fan = i_fan_on;
                o_state = 3'b000;

            3'b100:
                o_heater_full = 0;
                o_heater_medium = 0;
                o_heater_low = 1;
                o_aircon_full = 1;
                o_aircon_medium = 0;
                o_aircon_low = 0;
                o_fan = i_fan_on;
                o_state = 3'b100;

            3'b101:
                o_heater_full = 0;
                o_heater_medium = 1;
                o_heater_low = 0;
                o_aircon_full = 0;
                o_aircon_medium = 1;
                o_aircon_low = 0;
                o_fan = i_fan_on;
                o_state = 3'b101;

            3'b110:
                o_heater_full = 0;
                o_heater_medium = 0;
                o_heater_low = 1;
                o_aircon_full = 0;
                o_aircon_medium = 0;
                o_aircon_low = 1;
                o_fan = i_fan_on;
                o_state = 3'b110;

            default:
                o_heater_full = 0;
                o_heater_medium = 0;
                o_heater_low = 0;
                o_aircon_full = 0;
                o_aircon_medium = 0;
                o_aircon_low = 0;
                o_fan = i_fan_on;
                o_state = 3'b000;
        endcase
    end
endmodule

output.rtl/ttc_counter_lite.sv:
module ttc_counter_lite #(
    parameter WIDTH_COUNT = 32,
    parameter WIDTH_MATCH_VALUE = 32,
    parameter WIDTH_RELOAD_VALUE = 32
) (
    input clk,
    input reset,
    input [AXI_ADDR_WIDTH-1:0] axi_addr,
    input [AXI_WDATA_WIDTH-1:0] axi_wdata,
    input axi_write_en,
    input axi_read_en,
    output reg [AXI_RDATA_WIDTH-1:0] axi_rdata,
    output reg interrupt
);

    reg [WIDTH_COUNT-1:0] count;
    reg [WIDTH_MATCH_VALUE-1:0] match_value;
    reg [WIDTH_RELOAD_VALUE-1:0] reload_value;
    reg enable, interval_mode, interrupt_enable;
    reg match_flag;
    reg [WIDTH_STATUS_WIDTH-1:0] status;

    // Initialize all registers to reset state
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            count <= {WIDTH_COUNT{1'b0}};
            match_value <= {WIDTH_MATCH_VALUE{1'b0}};
            reload_value <= {WIDTH_RELOAD_VALUE{1'b0}};
            enable <= 1'b0;
            interval_mode <= 1'b0;
            interrupt_enable <= 1'b0;
            match_flag <= 1'b0;
            status <= {WIDTH_STATUS_WIDTH{1'b0}};
        end else begin
            if (enable) begin
                if (interval_mode) begin
                    if (match_value == count) begin
                        match_flag <= 1'b1;
                    end else begin
                        match_flag <= 1'b0;
                    end
                end else begin
                    if (match_value == count) begin
                        count <= reload_value;
                    end else {
                        count <= count + 1;
                    }
                end
            end
        end
    end

    // AXI-Lite interface
    always @(posedge clk) begin
        if (axi_write_en && axi_addr == AXI_WRITE_ADDR) begin
            match_value <= axi_wdata;
        end
        if (axi_read_en && axi_addr == AXI_READ_ADDR) begin
            axi_rdata <= count[WIDTH_COUNT-1:0];
        end
    end

    // Interrupt logic
    always @(posedge clk) begin
        if (match_flag && interrupt_enable) begin
            interrupt <= 1'b1;
        end else begin
            interrupt <= 1'b0;
        end
    end

    // Status register logic
    always @(posedge clk) begin
        if (reset) begin
            status <= {WIDTH_STATUS_WIDTH{1'b0}};
        end else begin
            status <= (match_flag == 1'b1) ? {WIDTH_STATUS_WIDTH{1'b1}} : {WIDTH_STATUS_WIDTH{1'b0}};
        end
    end

    // Control register logic
    always @(posedge clk) begin
        if (reset) begin
            enable <= 1'b0;
            interval_mode <= 1'b0;
            interrupt_enable <= 1'b0;
        end else begin
            enable <= axi_write_en;
            interval_mode <= match_value != 0;
            interrupt_enable <= match_value != 0;
        end
    end

endmodule

output.rtl/unpack_one_hot.v:
module unpack_one_hot(
    input signed [255:0] source_reg,
    input [1:0] one_hot_selector,
    input sign,
    input [1:0] size,
    output reg signed [511:0] destination_reg
);

    // Integer variable to iterate through the source_reg
    integer i;

    // Default initialization
    initial begin
        destination_reg = 0;
    end

    // Loop operation based on one_hot_selector
    always @ (source_reg, one_hot_selector, sign, size) begin
        if (one_hot_selector == 3'b001) begin
            for (i = 0; i < 256; i += 1) begin
                destination_reg[i] = source_reg[i] & (sign ? '1 : '0);
            end
        end else if (one_hot_selector == 3'b010) begin
            for (i = 0; i < 256; i += 2) begin
                destination_reg[i + 87] = (source_reg[i] << 6) | source_reg[i + 1];
                destination_reg[i + 88] = source_reg[i + 1] & (sign ? '1 : '0);
            end
        end else if (one_hot_selector == 3'b100) begin
            case (size)
                2'b0: for (i = 0; i < 128; i += 4) begin
                    destination_reg[i + 511] = (source_reg[i] << 8) | source_reg[i + 1];
                    destination_reg[i + 512] = source_reg[i + 2] & (sign ? '1 : '0);
                    destination_reg[i + 513] = source_reg[i + 3] & (sign ? '1 : '0);
                    destination_reg[i + 514] = source_reg[i + 4] & (sign ? '1 : '0);
                end
                2'b1: for (i = 0; i < 64; i += 8) begin
                    destination_reg[i + 511] = source_reg[i] << 8;
                    destination_reg[i + 512] = source_reg[i + 1] << 8;
                    destination_reg[i + 513] = source_reg[i + 2] << 8;
                    destination_reg[i + 514] = source_reg[i + 3] << 8;
                    destination_reg[i + 515] = source_reg[i + 4] << 8;
                    destination_reg[i + 516] = source_reg[i + 5] << 8;
                    destination_reg[i + 517] = source_reg[i + 6] << 8;
                    destination_reg[i + 518] = source_reg[i + 7] << 8;
                    destination_reg[i + 519] = source_reg[i + 8] << 8;
                end
            end
        end
    end

endmodule

